                    inside = false
                    iter = 50
                }
                iter += 1
            }
            if inside { sum += 1 }
            x += 1
        }
        y += 1
    }
    return sum
}
return mandelbrot(100)";

/// Sieve of Eratosthenes -- array subscript and index assignment.
/// Used by: Wren, AWFY, CLBG
const SIEVE: &str = "\
func sieve(size: int) -> int {
    var flags = [false]
    var i = 1
    while i < size {
        flags.push(true)
        i += 1
    }
    var count = 0
    i = 2
    while i < size {
        if flags[i] {
            count += 1
            var j = i + i
            while j < size {
                flags[j] = false
                j += i
            }
        }
        i += 1
    }
    return count
}
return sieve(5000)";

/// N-Queens solver -- exercises closures and nested function capture.
/// Used by: AWFY, Wren
const QUEENS: &str = "\
func queens(n: int) -> int {
    var solutions = 0
    var cols = [0]
    var i = 1
    while i < n {
        cols.push(0)
        i += 1
    }
    func valid(row: int, col: int) -> bool {
        var r = 0
        while r < row {
            let c = cols[r]
            if c == col { return false }
            if c - r == col - row { return false }
