        "RustData"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "value" => Ok(Value::Str(Rc::clone(&self.0))),
            _ => Err(format!("RustData has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, _value: Value) -> Result<(), String> {
        Err(format!("RustData field '{name}' is read-only"))
    }

    fn call_method(&mut self, name: &str, _args: &[Value]) -> Result<Value, String> {
        Err(format!("RustData has no method '{name}'"))
    }

    fn as_any(&self) -> &dyn Any {
        self
    }
}

pub fn extract_rust_data(v: &Value) -> RustData {
    match v {
        Value::Object(o) => o
            .borrow()
            .as_any()
            .downcast_ref::<RustData>()
            .unwrap()
            .clone(),
        _ => panic!("expected Object(RustData)"),
    }
}

pub fn sort_userdata(run: impl FnOnce(&mut dyn FnMut()), validate: impl FnOnce(Vec<Value>)) {
    let mut vm = Writ::new();
    vm.disable_type_checking();

    vm.register_host_fn_untyped(
        "make_data",
        fn1(|s: Value| -> Result<Value, String> {
            let s = match &s {
                Value::Str(s) => Rc::clone(s),
                _ => return Err("make_data expects a string".into()),
            };
            Ok(Value::Object(Rc::new(RefCell::new(RustData(s)))))
        }),
    );

    vm.register_host_fn_untyped(
        "data_lt",
        fn2(|a: Value, b: Value| -> Result<Value, String> {
            if !matches!(a, Value::Object(_)) || !matches!(b, Value::Object(_)) {
                return Err(format!(
                    "data_lt got non-Object: a={:?}, b={:?}",
                    a.type_name(),
                    b.type_name()
                ));
            }
            Ok(Value::Bool(extract_rust_data(&a) < extract_rust_data(&b)))
        }),
    );

    vm.run(include_str!("../scripts/sort_userdata.writ"))
        .expect("failed to load script");

    let result = vm.call("run", &[]).expect("run() failed");
    let arr = match result {
        Value::Array(a) => a.borrow().clone(),
        _ => panic!("run() must return an array"),
    };

    validate(arr);
    run(&mut || {
        vm.call("run", &[]).unwrap();
    });
}

use std::collections::{HashMap, HashSet};
use std::path::Path;

use lsp_types::Diagnostic;
use writ::lexer::Lexer;
use writ::parser::{Parser, Stmt, StmtKind};
use writ::types::{Type, TypeChecker};

use crate::diagnostics::{
    lex_error_to_diagnostic, parse_error_to_diagnostic, type_error_to_diagnostic,
};

/// Result of running the analysis pipeline on a single file.
pub struct AnalysisResult {
    /// The parsed AST (if lexing and parsing succeeded).
    pub stmts: Option<Vec<Stmt>>,
    /// The type checker state after analysis (for completions, hover, etc.).
    /// Available even when type errors occurred.
    pub type_checker: Option<TypeChecker>,
    /// All diagnostics collected from lex, parse, and type-check stages.
    pub diagnostics: Vec<Diagnostic>,
}

/// Runs the full analysis pipeline: lex → parse → type-check.
///
/// Collects all diagnostics from each stage. The pipeline continues as far
/// as possible even when earlier stages produce errors.
///
/// When `file_path` points to a real file on disk, import statements are
/// resolved by reading `.writ` files relative to the file's directory.
pub fn analyze(source: &str, file_path: &str) -> AnalysisResult {
    let mut diagnostics = Vec::new();

    // Stage 1: Lex
    let mut lexer = Lexer::with_file(source, file_path);
    let tokens = match lexer.tokenize() {
        Ok(tokens) => tokens,
        Err(err) => {
            diagnostics.push(lex_error_to_diagnostic(&err));
            return AnalysisResult {
                stmts: None,
                type_checker: None,
                diagnostics,
            };
        }
    };

    // Stage 2: Parse
    let mut parser = Parser::new(tokens);
    let stmts = match parser.parse_program() {
        Ok(stmts) => stmts,
        Err(err) => {
            diagnostics.push(parse_error_to_diagnostic(&err));
            return AnalysisResult {
                stmts: None,
                type_checker: None,
                diagnostics,
            };
        }
    };

    // Stage 3: Resolve imports from disk and type-check
    let mut checker = TypeChecker::new();

    // Discover import paths and resolve them from disk.
    let import_paths = collect_import_paths(&stmts);
    if !import_paths.is_empty() {
        let base_dir = Path::new(file_path).parent();
        for module_path in &import_paths {
            if let Some(exports) = resolve_module_from_disk(module_path, base_dir) {
                checker.register_module(module_path, exports);
            }
        }
    }

    let type_errors = checker.check_program_collecting(&stmts);
    for err in &type_errors {
        diagnostics.push(type_error_to_diagnostic(err));
    }

    AnalysisResult {
        stmts: Some(stmts),
        type_checker: Some(checker),
        diagnostics,
    }
}

/// Collects all unique import module paths from a parsed AST.
fn collect_import_paths(stmts: &[Stmt]) -> Vec<String> {
    let mut paths = HashSet::new();
    for stmt in stmts {
        match &stmt.kind {
            StmtKind::Import(import) => {
                paths.insert(import.from.clone());
            }
            StmtKind::WildcardImport(import) => {
                paths.insert(import.from.clone());
            }
            StmtKind::Export(inner) => {
                // Exports can wrap imports (re-exports).
                if let StmtKind::Import(import) = &inner.kind {
                    paths.insert(import.from.clone());
                } else if let StmtKind::WildcardImport(import) = &inner.kind {
                    paths.insert(import.from.clone());
                }
            }
            _ => {}
        }
    }
    paths.into_iter().collect()
}

/// Resolves a module path to disk, analyzes it, and returns its exports.
///
/// The module path (e.g. `"items/weapon"`) is resolved relative to `base_dir`
/// by appending `.writ`. Returns `None` if the file doesn't exist or can't
/// be analyzed.
fn resolve_module_from_disk(
    module_path: &str,
    base_dir: Option<&Path>,
) -> Option<HashMap<String, Type>> {
    let base = base_dir?;
    let file = base.join(format!("{module_path}.writ"));
    let source = std::fs::read_to_string(&file).ok()?;
    let file_path_str = file.to_string_lossy().into_owned();

    // Lex + parse the dependency (don't recurse into its imports to avoid cycles).
    let mut lexer = Lexer::with_file(&source, &file_path_str);
    let tokens = lexer.tokenize().ok()?;
    let mut parser = Parser::new(tokens);
    let stmts = parser.parse_program().ok()?;

    // Type-check the dependency to get accurate types.
    let mut checker = TypeChecker::new();
    // Ignore type errors in the dependency — we still extract what we can.
    let _ = checker.check_program_collecting(&stmts);

    // Extract exported names and their types.
    let exports = extract_exports(&stmts, &checker);
    if exports.is_empty() {
        None
    } else {
        Some(exports)
    }
}

/// Extracts exported names and their resolved types from an analyzed file.
///
/// Walks the AST looking for `export` wrappers and maps the declared name
/// to the type computed by the type checker.
fn extract_exports(stmts: &[Stmt], checker: &TypeChecker) -> HashMap<String, Type> {
    let mut exports = HashMap::new();
    let env = checker.env();
    let registry = checker.registry();

    for stmt in stmts {
        if let StmtKind::Export(inner) = &stmt.kind {
            match &inner.kind {
                StmtKind::Func(func) => {
                    if let Some(info) = env.lookup(&func.name) {
                        exports.insert(func.name.clone(), info.ty.clone());
                    }
                }
                StmtKind::Class(class) => {
                    // Exported class — register as a Class type so importers
                    // can instantiate it and access its members.
                    if registry.get_class(&class.name).is_some() {
                        exports.insert(class.name.clone(), Type::Class(class.name.clone()));
                    }
                }
                StmtKind::Trait(trait_decl) => {
                    if registry.get_trait(&trait_decl.name).is_some() {
                        exports.insert(
                            trait_decl.name.clone(),
                            Type::Trait(trait_decl.name.clone()),
                        );
                    }
                }
                StmtKind::Enum(enum_decl) => {
                    if registry.get_enum(&enum_decl.name).is_some() {
                        exports.insert(enum_decl.name.clone(), Type::Enum(enum_decl.name.clone()));
                    }
                }
                StmtKind::Struct(struct_decl) => {
                    if registry.get_struct(&struct_decl.name).is_some() {
                        exports.insert(
                            struct_decl.name.clone(),
                            Type::Struct(struct_decl.name.clone()),
                        );
                    }
                }
                StmtKind::Let { name, .. }
                | StmtKind::Var { name, .. }
                | StmtKind::Const { name, .. } => {
                    if let Some(info) = env.lookup(name) {
                        exports.insert(name.clone(), info.ty.clone());
                    }
                }
                _ => {}
            }
        }
    }
    exports
}

use lsp_types::{CompletionItem, CompletionItemKind, CompletionParams, CompletionResponse};

use crate::analysis;
use crate::convert::position_to_offset;
use crate::document::WorldState;

/// Writ language keywords for completion suggestions.
const KEYWORDS: &[&str] = &[
    "class", "trait", "enum", "struct", "func", "let", "var", "const", "public", "private",
    "static", "extends", "with", "import", "export", "return", "if", "else", "when", "while",
    "for", "in", "break", "continue", "is", "as", "self", "start", "yield", "true", "false",
    "null",
];

/// Handles `textDocument/completion` requests.
pub fn handle_completion(
    world: &WorldState,
    params: CompletionParams,
) -> Option<CompletionResponse> {
    let uri = &params.text_document_position.text_document.uri;
    let pos = params.text_document_position.position;
    let doc = world.get_document(uri)?;

    let offset = position_to_offset(&doc.source, pos)?;

    // Determine trigger context by looking at the character before the cursor.
    let before_cursor = if offset > 0 {
        doc.source.as_bytes().get(offset - 1).copied()
    } else {
        None
    };

    let mut items = Vec::new();

    match before_cursor {
        Some(b'.') => {
            // Dot trigger: find the expression before the dot and list fields/methods.
            if let (Some(stmts), Some(checker)) = (&doc.stmts, &doc.type_checker) {
                complete_dot_access(&doc.source, offset, stmts, checker, &mut items);
            }
            // If parse failed (stmts is None), try re-analyzing with the incomplete
            // line removed so type info is available for the identifier before the dot.
            if items.is_empty()
                && doc.stmts.is_none()
                && let Some(fixed_checker) = analyze_without_line(&doc.source, offset)
            {
                complete_dot_access(&doc.source, offset, &[], &fixed_checker, &mut items);
            }
        }
        _ => {
            // Identifier prefix or general completion.
            let prefix = extract_identifier_prefix(&doc.source, offset);
            complete_general(doc, &prefix, &mut items);
        }
    }

    if items.is_empty() {
        None
    } else {
        Some(CompletionResponse::Array(items))
    }
}

/// Completes after a `.` — resolves the type of the expression before the dot
/// and lists its fields and methods.
fn complete_dot_access(
    source: &str,
    offset: usize,
    _stmts: &[writ::parser::Stmt],
    checker: &writ::types::TypeChecker,
    items: &mut Vec<CompletionItem>,
) {
    // Walk backwards to find the identifier before the dot.
    let before_dot = if offset >= 2 { offset - 2 } else { return };
    let name = extract_identifier_at(source, before_dot);
    if name.is_empty() {
        return;
    }

    // Look up the identifier's type in the type environment.
    let env = checker.env();
    let ty = match env.lookup(&name) {
        Some(info) => &info.ty,
        None => return,
    };

    let registry = checker.registry();

    match ty {
        writ::types::Type::Class(type_name) => {
            // Add fields (with inheritance).
            for field in registry.all_fields(type_name) {
                items.push(CompletionItem {
                    label: field.name.clone(),
                    kind: Some(CompletionItemKind::FIELD),
                    detail: Some(field.ty.to_string()),
                    ..Default::default()
                });
            }
            // Add methods (with inheritance).
            for method in registry.all_methods(type_name) {
                if method.is_static {
                    continue;
                }
                items.push(CompletionItem {
                    label: method.name.clone(),
                    kind: Some(CompletionItemKind::METHOD),
                    detail: Some(format!(
                        "({}) -> {}",
                        format_params(&method.params),
                        method.return_type
                    )),
                    ..Default::default()
                });
            }
        }
        writ::types::Type::Struct(type_name) => {
            if let Some(info) = registry.get_struct(type_name) {
                for field in &info.fields {
                    items.push(CompletionItem {
                        label: field.name.clone(),
                        kind: Some(CompletionItemKind::FIELD),
                        detail: Some(field.ty.to_string()),
                        ..Default::default()
                    });
                }
                for method in &info.methods {
                    if method.is_static {
                        continue;
                    }
                    items.push(CompletionItem {
                        label: method.name.clone(),
                        kind: Some(CompletionItemKind::METHOD),
                        detail: Some(format!(
                            "({}) -> {}",
                            format_params(&method.params),
                            method.return_type
                        )),
                        ..Default::default()
                    });
                }
            }
        }
        _ => {}
    }
}

/// Provides general completions: locals, globals, type names, keywords.
fn complete_general(
    doc: &crate::document::DocumentState,
    prefix: &str,
    items: &mut Vec<CompletionItem>,
) {
    // Keywords.
    for &kw in KEYWORDS {
        if prefix.is_empty() || kw.starts_with(prefix) {
            items.push(CompletionItem {
                label: kw.to_string(),
                kind: Some(CompletionItemKind::KEYWORD),
                ..Default::default()
            });
        }
    }

    // Locals and globals from type environment.
    if let Some(checker) = &doc.type_checker {
        let env = checker.env();
        for (name, info) in env.all_visible() {
            if prefix.is_empty() || name.starts_with(prefix) {
                let kind = match &info.ty {
                    writ::types::Type::Function { .. } => CompletionItemKind::FUNCTION,
                    _ => CompletionItemKind::VARIABLE,
                };
                items.push(CompletionItem {
                    label: name.to_string(),
                    kind: Some(kind),
                    detail: Some(info.ty.to_string()),
                    ..Default::default()
                });
            }
        }

        // Type names (classes, traits, enums).
        let registry = checker.registry();
        for name in registry.class_names() {
            if prefix.is_empty() || name.starts_with(prefix) {
                items.push(CompletionItem {
                    label: name.to_string(),
                    kind: Some(CompletionItemKind::CLASS),
                    ..Default::default()
                });
            }
        }
        for name in registry.trait_names() {
            if prefix.is_empty() || name.starts_with(prefix) {
                items.push(CompletionItem {
                    label: name.to_string(),
                    kind: Some(CompletionItemKind::INTERFACE),
                    ..Default::default()
                });
            }
        }
        for name in registry.enum_names() {
            if prefix.is_empty() || name.starts_with(prefix) {
                items.push(CompletionItem {
                    label: name.to_string(),
                    kind: Some(CompletionItemKind::ENUM),
                    ..Default::default()
                });
            }
        }
        for name in registry.struct_names() {
            if prefix.is_empty() || name.starts_with(prefix) {
                items.push(CompletionItem {
                    label: name.to_string(),
                    kind: Some(CompletionItemKind::STRUCT),
                    ..Default::default()
                });
            }
        }
    }
}

/// Extracts the identifier being typed at the cursor position.
fn extract_identifier_prefix(source: &str, offset: usize) -> String {
    let bytes = source.as_bytes();
    let mut start = offset;
    while start > 0 && is_ident_char(bytes[start - 1]) {
        start -= 1;
    }
    source[start..offset].to_string()
}

/// Extracts the identifier at the given byte offset (searching backwards and forwards).
fn extract_identifier_at(source: &str, offset: usize) -> String {
    let bytes = source.as_bytes();
    if offset >= bytes.len() || !is_ident_char(bytes[offset]) {
        // Try searching backwards from offset.
        let end = offset + 1;
        let mut start = end;
        while start > 0 && is_ident_char(bytes[start - 1]) {
            start -= 1;
        }
        if start < end && end <= bytes.len() {
            return source[start..end].to_string();
        }
        return String::new();
    }
    let mut start = offset;
    while start > 0 && is_ident_char(bytes[start - 1]) {
        start -= 1;
    }
    let mut end = offset;
    while end < bytes.len() && is_ident_char(bytes[end]) {
        end += 1;
    }
    source[start..end].to_string()
}

fn is_ident_char(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_'
}

fn format_params(params: &[writ::types::Type]) -> String {
    params
        .iter()
        .map(|t| t.to_string())
        .collect::<Vec<_>>()
        .join(", ")
}

/// Re-analyzes the source with the line containing `offset` removed.
///
/// This allows dot-completion to work even when the current line has a parse error
/// (e.g., `p.` with no member). By removing the incomplete line, the rest of the
/// program parses and type-checks successfully, giving us the type information
/// needed for completions.
fn analyze_without_line(source: &str, offset: usize) -> Option<writ::types::TypeChecker> {
    // Find the line containing the offset and remove it.
    let mut fixed = String::new();
    let mut current_offset = 0;
    for line in source.split('\n') {
        let line_end = current_offset + line.len();
        if !(current_offset..=line_end).contains(&offset) {
            fixed.push_str(line);
            fixed.push('\n');
        }
        current_offset = line_end + 1;
    }

    let result = analysis::analyze(&fixed, "");
    result.type_checker
}

use writ::lexer::Span;

/// Converts a Writ `Span` (1-indexed) to an LSP `Range` (0-indexed).
pub fn span_to_range(span: &Span) -> lsp_types::Range {
    let start = lsp_types::Position {
        line: span.line.saturating_sub(1),
        character: span.column.saturating_sub(1),
    };
    let end = lsp_types::Position {
        line: span.line.saturating_sub(1),
        character: span.column.saturating_sub(1) + span.length,
    };
    lsp_types::Range { start, end }
}

/// Converts an LSP `Position` (0-indexed) to a byte offset in the source string.
pub fn position_to_offset(source: &str, pos: lsp_types::Position) -> Option<usize> {
    let mut offset = 0;
    for (i, line) in source.split('\n').enumerate() {
        if i == pos.line as usize {
            let char_offset = pos.character as usize;
            if char_offset <= line.len() {
                return Some(offset + char_offset);
            } else {
                return None;
            }
        }
        offset += line.len() + 1; // +1 for '\n'
    }
    None
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Converts a byte offset to an LSP `Position` (0-indexed).
    fn offset_to_position(source: &str, offset: usize) -> lsp_types::Position {
        let mut line = 0u32;
        let mut col = 0u32;
        for (i, ch) in source.char_indices() {
            if i == offset {
                return lsp_types::Position {
                    line,
                    character: col,
                };
            }
            if ch == '\n' {
                line += 1;
                col = 0;
            } else {
                col += 1;
            }
        }
        lsp_types::Position {
            line,
            character: col,
        }
    }

    #[test]
    fn span_to_range_converts_1_indexed_to_0_indexed() {
        let span = Span {
            file: String::new(),
            line: 1,
            column: 1,
            length: 3,
        };
        let range = span_to_range(&span);
        assert_eq!(range.start.line, 0);
        assert_eq!(range.start.character, 0);
        assert_eq!(range.end.character, 3);
    }

    #[test]
    fn position_to_offset_first_line() {
        let source = "let x = 42";
        let pos = lsp_types::Position {
            line: 0,
            character: 4,
        };
        assert_eq!(position_to_offset(source, pos), Some(4));
    }

    #[test]
    fn position_to_offset_second_line() {
        let source = "let x = 42\nlet y = 10";
        let pos = lsp_types::Position {
            line: 1,
            character: 4,
        };
        assert_eq!(position_to_offset(source, pos), Some(15));
    }

    #[test]
    fn position_to_offset_out_of_bounds() {
        let source = "abc";
        let pos = lsp_types::Position {
            line: 0,
            character: 10,
        };
        assert_eq!(position_to_offset(source, pos), None);
    }

    #[test]
    fn offset_to_position_roundtrip() {
        let source = "hello\nworld";
        let pos = offset_to_position(source, 6);
        assert_eq!(pos.line, 1);
        assert_eq!(pos.character, 0);
    }
}

use lsp_types::{GotoDefinitionParams, GotoDefinitionResponse, Location};

use crate::convert::{position_to_offset, span_to_range};
use crate::document::WorldState;

/// Handles `textDocument/definition` requests.
pub fn handle_goto_definition(
    world: &WorldState,
    params: GotoDefinitionParams,
) -> Option<GotoDefinitionResponse> {
    let uri = &params.text_document_position_params.text_document.uri;
    let pos = params.text_document_position_params.position;
    let doc = world.get_document(uri)?;

    let offset = position_to_offset(&doc.source, pos)?;
    let name = extract_identifier_at_offset(&doc.source, offset);
    if name.is_empty() {
        return None;
    }

    let stmts = doc.stmts.as_ref()?;

    // Search the AST for the declaration of this name.
    for stmt in stmts {
        if let Some(span) = find_declaration_span(stmt, &name) {
            return Some(GotoDefinitionResponse::Scalar(Location {
                uri: uri.clone(),
                range: span_to_range(&span),
            }));
        }
    }

    None
}

/// Extracts the identifier at the given byte offset.
fn extract_identifier_at_offset(source: &str, offset: usize) -> String {
    let bytes = source.as_bytes();
    if offset >= bytes.len() {
        return String::new();
    }

    let mut start = offset;
    while start > 0 && is_ident_char(bytes[start - 1]) {
        start -= 1;
    }
    let mut end = offset;
    while end < bytes.len() && is_ident_char(bytes[end]) {
        end += 1;
    }

    if start == end {
        return String::new();
    }

    source[start..end].to_string()
}

fn is_ident_char(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_'
}

/// Searches a statement (and its children) for a declaration matching `name`.
/// Returns the span of the declaration if found.
fn find_declaration_span(stmt: &writ::parser::Stmt, name: &str) -> Option<writ::lexer::Span> {
    use writ::parser::StmtKind;

    match &stmt.kind {
        StmtKind::Let {
            name: decl_name, ..
        }
        | StmtKind::Var {
            name: decl_name, ..
        }
        | StmtKind::Const {
            name: decl_name, ..
        } => {
            if decl_name == name {
                return Some(stmt.span.clone());
            }
        }
        StmtKind::Func(func) => {
            if func.name == name {
                return Some(stmt.span.clone());
            }
            // Search inside function body.
            for body_stmt in &func.body {
                if let Some(span) = find_declaration_span(body_stmt, name) {
                    return Some(span);
                }
            }
        }
        StmtKind::Class(class) => {
            if class.name == name {
                return Some(stmt.span.clone());
            }
        }
        StmtKind::Trait(trait_decl) => {
            if trait_decl.name == name {
                return Some(stmt.span.clone());
            }
        }
        StmtKind::Enum(enum_decl) => {
            if enum_decl.name == name {
                return Some(stmt.span.clone());
            }
        }
        StmtKind::Block(stmts) => {
            for s in stmts {
                if let Some(span) = find_declaration_span(s, name) {
                    return Some(span);
                }
            }
        }
        StmtKind::If {
            then_block,
            else_branch,
            ..
        } => {
            for s in then_block {
                if let Some(span) = find_declaration_span(s, name) {
                    return Some(span);
                }
            }
            if let Some(branch) = else_branch {
                match branch {
                    writ::parser::ElseBranch::ElseIf(s) => {
                        if let Some(span) = find_declaration_span(s, name) {
                            return Some(span);
                        }
                    }
                    writ::parser::ElseBranch::ElseBlock(stmts) => {
                        for s in stmts {
                            if let Some(span) = find_declaration_span(s, name) {
                                return Some(span);
                            }
                        }
                    }
                }
            }
        }
        StmtKind::While { body, .. } | StmtKind::For { body, .. } => {
            for s in body {
                if let Some(span) = find_declaration_span(s, name) {
                    return Some(span);
                }
            }
        }
        StmtKind::Export(inner) => {
            if let Some(span) = find_declaration_span(inner, name) {
                return Some(span);
            }
        }
        _ => {}
    }
    None
}

