use lsp_types::{Location, ReferenceParams};

use crate::convert::{position_to_offset, span_to_range};
use crate::document::WorldState;

/// Handles `textDocument/references` requests.
pub fn handle_references(world: &WorldState, params: ReferenceParams) -> Option<Vec<Location>> {
    let uri = &params.text_document_position.text_document.uri;
    let pos = params.text_document_position.position;
    let doc = world.get_document(uri)?;

    let offset = position_to_offset(&doc.source, pos)?;
    let name = extract_identifier_at_offset(&doc.source, offset);
    if name.is_empty() {
        return None;
    }

    let stmts = doc.stmts.as_ref()?;

    let mut locations = Vec::new();
    collect_identifier_locations(stmts, &name, uri, &mut locations);

    if locations.is_empty() {
        None
    } else {
        Some(locations)
    }
}

/// Walks the AST and collects all locations where `name` appears as an identifier.
fn collect_identifier_locations(
    stmts: &[writ::parser::Stmt],
    name: &str,
    uri: &lsp_types::Uri,
    locations: &mut Vec<Location>,
) {
    for stmt in stmts {
        collect_from_stmt(stmt, name, uri, locations);
    }
}

fn collect_from_stmt(
    stmt: &writ::parser::Stmt,
    name: &str,
    uri: &lsp_types::Uri,
    locations: &mut Vec<Location>,
) {
    use writ::parser::StmtKind;

    match &stmt.kind {
        StmtKind::Let {
            name: decl_name,
            initializer,
            ..
        }
        | StmtKind::Var {
            name: decl_name,
            initializer,
            ..
        } => {
            if decl_name == name {
                locations.push(Location {
                    uri: uri.clone(),
                    range: span_to_range(&stmt.span),
                });
            }
            collect_from_expr(initializer, name, uri, locations);
        }
        StmtKind::Const {
            name: decl_name,
            initializer,
        } => {
            if decl_name == name {
                locations.push(Location {
                    uri: uri.clone(),
                    range: span_to_range(&stmt.span),
                });
            }
            collect_from_expr(initializer, name, uri, locations);
        }
        StmtKind::ExprStmt(expr) => {
            collect_from_expr(expr, name, uri, locations);
        }
        StmtKind::Return(Some(expr)) => {
            collect_from_expr(expr, name, uri, locations);
        }
        StmtKind::Assignment { target, value, .. } => {
            collect_from_expr(target, name, uri, locations);
            collect_from_expr(value, name, uri, locations);
        }
        StmtKind::Func(func) => {
            if func.name == name {
                locations.push(Location {
                    uri: uri.clone(),
                    range: span_to_range(&stmt.span),
                });
            }
            collect_identifier_locations(&func.body, name, uri, locations);
        }
        StmtKind::Class(class) => {
            if class.name == name {
                locations.push(Location {
                    uri: uri.clone(),
                    range: span_to_range(&stmt.span),
                });
            }
            for method in &class.methods {
                collect_identifier_locations(&method.body, name, uri, locations);
            }
        }
        StmtKind::Trait(trait_decl) => {
            if trait_decl.name == name {
                locations.push(Location {
                    uri: uri.clone(),
                    range: span_to_range(&stmt.span),
                });
            }
        }
        StmtKind::Enum(enum_decl) => {
            if enum_decl.name == name {
                locations.push(Location {
                    uri: uri.clone(),
                    range: span_to_range(&stmt.span),
                });
            }
        }
        StmtKind::Block(stmts) => {
            collect_identifier_locations(stmts, name, uri, locations);
        }
        StmtKind::If {
            condition,
            then_block,
            else_branch,
        } => {
            collect_from_expr(condition, name, uri, locations);
            collect_identifier_locations(then_block, name, uri, locations);
            if let Some(branch) = else_branch {
                match branch {
                    writ::parser::ElseBranch::ElseIf(s) => {
                        collect_from_stmt(s, name, uri, locations);
                    }
                    writ::parser::ElseBranch::ElseBlock(stmts) => {
                        collect_identifier_locations(stmts, name, uri, locations);
                    }
                }
            }
        }
        StmtKind::While { condition, body } => {
            collect_from_expr(condition, name, uri, locations);
            collect_identifier_locations(body, name, uri, locations);
        }
        StmtKind::For {
            variable,
            iterable,
            body,
        } => {
            if variable == name {
                locations.push(Location {
                    uri: uri.clone(),
                    range: span_to_range(&stmt.span),
                });
            }
            collect_from_expr(iterable, name, uri, locations);
            collect_identifier_locations(body, name, uri, locations);
        }
        StmtKind::Export(inner) => {
            collect_from_stmt(inner, name, uri, locations);
        }
        StmtKind::When { subject, arms } => {
            if let Some(expr) = subject {
                collect_from_expr(expr, name, uri, locations);
            }
            for arm in arms {
                match &arm.body {
                    writ::parser::WhenBody::Expr(expr) => {
                        collect_from_expr(expr, name, uri, locations);
                    }
                    writ::parser::WhenBody::Block(stmts) => {
                        collect_identifier_locations(stmts, name, uri, locations);
                    }
                }
            }
        }
        StmtKind::Start(expr) => {
            collect_from_expr(expr, name, uri, locations);
        }
        _ => {}
    }
}

fn collect_from_expr(
    expr: &writ::parser::Expr,
    name: &str,
    uri: &lsp_types::Uri,
    locations: &mut Vec<Location>,
) {
    use writ::parser::ExprKind;

    match &expr.kind {
        ExprKind::Identifier(ident) => {
            if ident == name {
                locations.push(Location {
                    uri: uri.clone(),
                    range: span_to_range(&expr.span),
                });
            }
        }
        ExprKind::Binary { lhs, rhs, .. } => {
            collect_from_expr(lhs, name, uri, locations);
            collect_from_expr(rhs, name, uri, locations);
        }
        ExprKind::Unary { operand, .. } => {
            collect_from_expr(operand, name, uri, locations);
        }
        ExprKind::Grouped(inner) => {
            collect_from_expr(inner, name, uri, locations);
        }
        ExprKind::Call { callee, args } => {
            collect_from_expr(callee, name, uri, locations);
            for arg in args {
                match arg {
                    writ::parser::CallArg::Positional(expr) => {
                        collect_from_expr(expr, name, uri, locations);
                    }
                    writ::parser::CallArg::Named { value, .. } => {
                        collect_from_expr(value, name, uri, locations);
                    }
                }
            }
        }
        ExprKind::MemberAccess { object, .. } | ExprKind::SafeAccess { object, .. } => {
            collect_from_expr(object, name, uri, locations);
        }
        ExprKind::Ternary {
            condition,
            then_expr,
            else_expr,
        } => {
            collect_from_expr(condition, name, uri, locations);
            collect_from_expr(then_expr, name, uri, locations);
            collect_from_expr(else_expr, name, uri, locations);
        }
        ExprKind::NullCoalesce { lhs, rhs }
        | ExprKind::Range {
            start: lhs,
            end: rhs,
            ..
        } => {
            collect_from_expr(lhs, name, uri, locations);
            collect_from_expr(rhs, name, uri, locations);
        }
        ExprKind::Lambda { body, .. } => match body {
            writ::parser::LambdaBody::Expr(expr) => {
                collect_from_expr(expr, name, uri, locations);
            }
            writ::parser::LambdaBody::Block(stmts) => {
                collect_identifier_locations(stmts, name, uri, locations);
            }
        },
        ExprKind::ArrayLiteral(elements) => {
            for element in elements {
                match element {
                    writ::parser::ArrayElement::Expr(expr)
                    | writ::parser::ArrayElement::Spread(expr) => {
                        collect_from_expr(expr, name, uri, locations);
                    }
                }
            }
        }
        ExprKind::DictLiteral(elements) => {
            for element in elements {
                match element {
                    writ::parser::DictElement::KeyValue { key, value } => {
                        collect_from_expr(key, name, uri, locations);
                        collect_from_expr(value, name, uri, locations);
                    }
                    writ::parser::DictElement::Spread(expr) => {
                        collect_from_expr(expr, name, uri, locations);
                    }
                }
            }
        }
        ExprKind::ErrorPropagate(inner) | ExprKind::Cast { expr: inner, .. } => {
            collect_from_expr(inner, name, uri, locations);
        }
        ExprKind::StringInterpolation(segments) => {
            for segment in segments {
                if let writ::parser::InterpolationSegment::Expression(expr) = segment {
                    collect_from_expr(expr, name, uri, locations);
                }
            }
        }
        ExprKind::Tuple(exprs) => {
            for expr in exprs {
                collect_from_expr(expr, name, uri, locations);
            }
        }
        ExprKind::Yield(Some(inner)) => {
            collect_from_expr(inner, name, uri, locations);
        }
        ExprKind::When { subject, arms } => {
            if let Some(subj) = subject {
                collect_from_expr(subj, name, uri, locations);
            }
            for arm in arms {
                if let writ::parser::WhenBody::Block(stmts) = &arm.body {
                    for stmt in stmts {
                        collect_from_stmt(stmt, name, uri, locations);
                    }
                } else if let writ::parser::WhenBody::Expr(expr) = &arm.body {
                    collect_from_expr(expr, name, uri, locations);
                }
            }
        }
        ExprKind::Index { object, index } => {
            collect_from_expr(object, name, uri, locations);
            collect_from_expr(index, name, uri, locations);
        }
        ExprKind::NamespaceAccess { .. }
        | ExprKind::Literal(_)
        | ExprKind::Yield(None)
        | ExprKind::Super { .. } => {}
    }
}

/// Extracts the identifier at the given byte offset.
fn extract_identifier_at_offset(source: &str, offset: usize) -> String {
    let bytes = source.as_bytes();
    if offset >= bytes.len() {
        return String::new();
    }

    let mut start = offset;
    while start > 0 && is_ident_char(bytes[start - 1]) {
        start -= 1;
    }
    let mut end = offset;
    while end < bytes.len() && is_ident_char(bytes[end]) {
        end += 1;
    }

    if start == end {
        return String::new();
    }

    source[start..end].to_string()
}

fn is_ident_char(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_'
}

use std::collections::HashMap;

use lsp_types::{RenameParams, TextEdit, WorkspaceEdit};

use crate::convert::{position_to_offset, span_to_range};
use crate::document::WorldState;

/// Handles `textDocument/rename` requests.
// Uri contains interior mutability for caching, but Hash/Eq are based on the
// immutable string content. This is safe and matches how the LSP protocol works.
#[allow(clippy::mutable_key_type)]
pub fn handle_rename(world: &WorldState, params: RenameParams) -> Option<WorkspaceEdit> {
    let uri = &params.text_document_position.text_document.uri;
    let pos = params.text_document_position.position;
    let doc = world.get_document(uri)?;

    let offset = position_to_offset(&doc.source, pos)?;
    let name = extract_identifier_at_offset(&doc.source, offset);
    if name.is_empty() {
        return None;
    }

    let stmts = doc.stmts.as_ref()?;
    let new_name = &params.new_name;

    // Collect all locations of this identifier in the AST.
    let mut edits = Vec::new();
    collect_rename_edits(stmts, &name, new_name, &mut edits);

    if edits.is_empty() {
        return None;
    }

    let mut changes = HashMap::new();
    changes.insert(uri.clone(), edits);

    Some(WorkspaceEdit {
        changes: Some(changes),
        ..Default::default()
    })
}

/// Walks the AST and collects text edits for renaming `old_name` to `new_name`.
fn collect_rename_edits(
    stmts: &[writ::parser::Stmt],
    old_name: &str,
    new_name: &str,
    edits: &mut Vec<TextEdit>,
) {
    for stmt in stmts {
        collect_from_stmt(stmt, old_name, new_name, edits);
    }
}

fn collect_from_stmt(
    stmt: &writ::parser::Stmt,
    old_name: &str,
    new_name: &str,
    edits: &mut Vec<TextEdit>,
) {
    use writ::parser::StmtKind;

    match &stmt.kind {
        StmtKind::Let {
            name, initializer, ..
        }
        | StmtKind::Var {
            name, initializer, ..
        } => {
            if name == old_name {
                edits.push(TextEdit {
                    range: span_to_range(&stmt.span),
                    new_text: new_name.to_string(),
                });
            }
            collect_from_expr(initializer, old_name, new_name, edits);
        }
        StmtKind::Const { name, initializer } => {
            if name == old_name {
                edits.push(TextEdit {
                    range: span_to_range(&stmt.span),
                    new_text: new_name.to_string(),
                });
            }
            collect_from_expr(initializer, old_name, new_name, edits);
        }
        StmtKind::ExprStmt(expr) => {
            collect_from_expr(expr, old_name, new_name, edits);
        }
        StmtKind::Return(Some(expr)) => {
            collect_from_expr(expr, old_name, new_name, edits);
        }
        StmtKind::Assignment { target, value, .. } => {
            collect_from_expr(target, old_name, new_name, edits);
            collect_from_expr(value, old_name, new_name, edits);
        }
        StmtKind::Func(func) => {
            if func.name == old_name {
                edits.push(TextEdit {
                    range: span_to_range(&stmt.span),
                    new_text: new_name.to_string(),
                });
            }
            collect_rename_edits(&func.body, old_name, new_name, edits);
        }
        StmtKind::Class(class) => {
            if class.name == old_name {
                edits.push(TextEdit {
                    range: span_to_range(&stmt.span),
                    new_text: new_name.to_string(),
                });
            }
            for method in &class.methods {
                collect_rename_edits(&method.body, old_name, new_name, edits);
            }
        }
        StmtKind::Block(stmts) => {
            collect_rename_edits(stmts, old_name, new_name, edits);
        }
        StmtKind::If {
            condition,
            then_block,
            else_branch,
        } => {
            collect_from_expr(condition, old_name, new_name, edits);
            collect_rename_edits(then_block, old_name, new_name, edits);
            if let Some(branch) = else_branch {
                match branch {
                    writ::parser::ElseBranch::ElseIf(s) => {
                        collect_from_stmt(s, old_name, new_name, edits);
                    }
                    writ::parser::ElseBranch::ElseBlock(stmts) => {
                        collect_rename_edits(stmts, old_name, new_name, edits);
                    }
                }
            }
        }
        StmtKind::While { condition, body } => {
            collect_from_expr(condition, old_name, new_name, edits);
            collect_rename_edits(body, old_name, new_name, edits);
        }
        StmtKind::For {
            variable,
            iterable,
            body,
        } => {
            if variable == old_name {
                edits.push(TextEdit {
                    range: span_to_range(&stmt.span),
                    new_text: new_name.to_string(),
                });
            }
            collect_from_expr(iterable, old_name, new_name, edits);
            collect_rename_edits(body, old_name, new_name, edits);
        }
        StmtKind::Export(inner) => {
            collect_from_stmt(inner, old_name, new_name, edits);
        }
        StmtKind::When { subject, arms } => {
            if let Some(expr) = subject {
                collect_from_expr(expr, old_name, new_name, edits);
            }
            for arm in arms {
                match &arm.body {
                    writ::parser::WhenBody::Expr(expr) => {
                        collect_from_expr(expr, old_name, new_name, edits);
                    }
                    writ::parser::WhenBody::Block(stmts) => {
                        collect_rename_edits(stmts, old_name, new_name, edits);
                    }
                }
            }
        }
        StmtKind::Start(expr) => {
            collect_from_expr(expr, old_name, new_name, edits);
        }
        _ => {}
    }
}

fn collect_from_expr(
    expr: &writ::parser::Expr,
    old_name: &str,
    new_name: &str,
    edits: &mut Vec<TextEdit>,
) {
    use writ::parser::ExprKind;

    match &expr.kind {
        ExprKind::Identifier(ident) => {
            if ident == old_name {
                edits.push(TextEdit {
                    range: span_to_range(&expr.span),
                    new_text: new_name.to_string(),
                });
            }
        }
        ExprKind::Binary { lhs, rhs, .. } => {
            collect_from_expr(lhs, old_name, new_name, edits);
            collect_from_expr(rhs, old_name, new_name, edits);
        }
        ExprKind::Unary { operand, .. } => {
            collect_from_expr(operand, old_name, new_name, edits);
        }
        ExprKind::Grouped(inner) => {
            collect_from_expr(inner, old_name, new_name, edits);
        }
        ExprKind::Call { callee, args } => {
            collect_from_expr(callee, old_name, new_name, edits);
            for arg in args {
                match arg {
                    writ::parser::CallArg::Positional(expr) => {
                        collect_from_expr(expr, old_name, new_name, edits);
                    }
                    writ::parser::CallArg::Named { value, .. } => {
                        collect_from_expr(value, old_name, new_name, edits);
                    }
                }
            }
        }
        ExprKind::MemberAccess { object, .. } | ExprKind::SafeAccess { object, .. } => {
            collect_from_expr(object, old_name, new_name, edits);
        }
        ExprKind::Ternary {
            condition,
            then_expr,
            else_expr,
        } => {
            collect_from_expr(condition, old_name, new_name, edits);
            collect_from_expr(then_expr, old_name, new_name, edits);
            collect_from_expr(else_expr, old_name, new_name, edits);
        }
        ExprKind::NullCoalesce { lhs, rhs }
        | ExprKind::Range {
            start: lhs,
            end: rhs,
            ..
        } => {
            collect_from_expr(lhs, old_name, new_name, edits);
            collect_from_expr(rhs, old_name, new_name, edits);
        }
        ExprKind::Lambda { body, .. } => match body {
            writ::parser::LambdaBody::Expr(expr) => {
                collect_from_expr(expr, old_name, new_name, edits);
            }
            writ::parser::LambdaBody::Block(stmts) => {
                collect_rename_edits(stmts, old_name, new_name, edits);
            }
        },
        ExprKind::ArrayLiteral(elements) => {
            for element in elements {
                match element {
                    writ::parser::ArrayElement::Expr(expr)
                    | writ::parser::ArrayElement::Spread(expr) => {
                        collect_from_expr(expr, old_name, new_name, edits);
                    }
                }
            }
        }
        ExprKind::DictLiteral(elements) => {
            for element in elements {
                match element {
                    writ::parser::DictElement::KeyValue { key, value } => {
                        collect_from_expr(key, old_name, new_name, edits);
                        collect_from_expr(value, old_name, new_name, edits);
                    }
                    writ::parser::DictElement::Spread(expr) => {
                        collect_from_expr(expr, old_name, new_name, edits);
                    }
                }
            }
        }
        ExprKind::ErrorPropagate(inner) | ExprKind::Cast { expr: inner, .. } => {
            collect_from_expr(inner, old_name, new_name, edits);
        }
        ExprKind::StringInterpolation(segments) => {
            for segment in segments {
                if let writ::parser::InterpolationSegment::Expression(expr) = segment {
                    collect_from_expr(expr, old_name, new_name, edits);
                }
            }
        }
        ExprKind::Tuple(exprs) => {
            for expr in exprs {
                collect_from_expr(expr, old_name, new_name, edits);
            }
        }
        ExprKind::Yield(Some(inner)) => {
            collect_from_expr(inner, old_name, new_name, edits);
        }
        ExprKind::When { subject, arms } => {
            if let Some(subj) = subject {
                collect_from_expr(subj, old_name, new_name, edits);
            }
            for arm in arms {
                if let writ::parser::WhenBody::Block(stmts) = &arm.body {
                    for stmt in stmts {
                        collect_from_stmt(stmt, old_name, new_name, edits);
                    }
                } else if let writ::parser::WhenBody::Expr(expr) = &arm.body {
                    collect_from_expr(expr, old_name, new_name, edits);
                }
            }
        }
        ExprKind::Index { object, index } => {
            collect_from_expr(object, old_name, new_name, edits);
            collect_from_expr(index, old_name, new_name, edits);
        }
        ExprKind::NamespaceAccess { .. }
        | ExprKind::Literal(_)
        | ExprKind::Yield(None)
        | ExprKind::Super { .. } => {}
    }
}

/// Extracts the identifier at the given byte offset.
fn extract_identifier_at_offset(source: &str, offset: usize) -> String {
    let bytes = source.as_bytes();
    if offset >= bytes.len() {
        return String::new();
    }

    let mut start = offset;
    while start > 0 && is_ident_char(bytes[start - 1]) {
        start -= 1;
    }
    let mut end = offset;
    while end < bytes.len() && is_ident_char(bytes[end]) {
        end += 1;
    }

    if start == end {
        return String::new();
    }

    source[start..end].to_string()
}

fn is_ident_char(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_'
}

use lsp_server::{Connection, ExtractError, Message, Notification, Request, RequestId, Response};
use lsp_types::{
    CompletionOptions, HoverProviderCapability, InitializeParams, OneOf, PublishDiagnosticsParams,
    ServerCapabilities, TextDocumentSyncCapability, TextDocumentSyncKind,
    notification::{
        DidChangeTextDocument, DidCloseTextDocument, DidOpenTextDocument, Notification as _,
        PublishDiagnostics,
    },
    request::{Completion, GotoDefinition, HoverRequest, References, Rename},
};
use serde_json::Value;

use crate::completion::handle_completion;
use crate::definition::handle_goto_definition;
use crate::document::WorldState;
use crate::hover::handle_hover;
use crate::references::handle_references;
use crate::rename::handle_rename;

/// Runs the LSP server on stdin/stdout.
pub fn run_server() -> Result<(), Box<dyn std::error::Error + Sync + Send>> {
    let (connection, io_threads) = Connection::stdio();

    let server_capabilities = serde_json::to_value(ServerCapabilities {
        text_document_sync: Some(TextDocumentSyncCapability::Kind(TextDocumentSyncKind::FULL)),
        completion_provider: Some(CompletionOptions {
            trigger_characters: Some(vec![".".to_string(), ":".to_string()]),
            ..Default::default()
        }),
        definition_provider: Some(OneOf::Left(true)),
        references_provider: Some(OneOf::Left(true)),
        hover_provider: Some(HoverProviderCapability::Simple(true)),
        rename_provider: Some(OneOf::Left(true)),
        ..Default::default()
    })?;

    let init_params = connection.initialize(server_capabilities)?;
    let _init_params: InitializeParams = serde_json::from_value(init_params)?;

    main_loop(&connection, _init_params)?;

    io_threads.join()?;
    Ok(())
}

fn main_loop(
    connection: &Connection,
    _init_params: InitializeParams,
) -> Result<(), Box<dyn std::error::Error + Sync + Send>> {
    let mut world = WorldState::new();

    for msg in &connection.receiver {
        match msg {
            Message::Request(req) => {
                if connection.handle_shutdown(&req)? {
                    return Ok(());
                }
                handle_request(connection, &world, req)?;
            }
            Message::Notification(not) => {
                handle_notification(connection, &mut world, not)?;
            }
            Message::Response(_) => {}
        }
    }

    Ok(())
}

fn handle_request(
    connection: &Connection,
    world: &WorldState,
    req: Request,
) -> Result<(), Box<dyn std::error::Error + Sync + Send>> {
    // Try each request type.
    let req = match cast_request::<Completion>(req) {
        Ok((id, params)) => {
            let result = handle_completion(world, params);
            send_response(connection, id, result)?;
            return Ok(());
        }
        Err(req) => req,
    };

    let req = match cast_request::<GotoDefinition>(req) {
        Ok((id, params)) => {
            let result = handle_goto_definition(world, params);
            send_response(connection, id, result)?;
            return Ok(());
        }
        Err(req) => req,
    };

    let req = match cast_request::<References>(req) {
        Ok((id, params)) => {
            let result = handle_references(world, params);
            send_response(connection, id, result)?;
            return Ok(());
        }
        Err(req) => req,
    };

    let req = match cast_request::<HoverRequest>(req) {
        Ok((id, params)) => {
            let result = handle_hover(world, params);
            send_response(connection, id, result)?;
            return Ok(());
        }
        Err(req) => req,
    };

    match cast_request::<Rename>(req) {
        Ok((id, params)) => {
            let result = handle_rename(world, params);
            send_response(connection, id, result)?;
        }
        Err(_req) => {
            // Unknown request type — ignored.
        }
    }

    Ok(())
}

fn handle_notification(
    connection: &Connection,
    world: &mut WorldState,
    not: Notification,
) -> Result<(), Box<dyn std::error::Error + Sync + Send>> {
    let not = match cast_notification::<DidOpenTextDocument>(not) {
        Ok(params) => {
            let uri = params.text_document.uri.clone();
            world.open_document(params.text_document.uri, params.text_document.text);
            publish_diagnostics(connection, world, &uri)?;
            return Ok(());
        }
        Err(not) => not,
    };

    let not = match cast_notification::<DidChangeTextDocument>(not) {
        Ok(params) => {
            let uri = params.text_document.uri.clone();
            // Full sync — use the last content change.
            if let Some(change) = params.content_changes.into_iter().last() {
                world.update_document(params.text_document.uri, change.text);
            }
            publish_diagnostics(connection, world, &uri)?;
            return Ok(());
        }
        Err(not) => not,
    };

    match cast_notification::<DidCloseTextDocument>(not) {
        Ok(params) => {
            let uri = &params.text_document.uri;
            world.close_document(uri);
            // Clear diagnostics for the closed file.
            let clear = PublishDiagnosticsParams {
                uri: uri.clone(),
                diagnostics: vec![],
                version: None,
            };
            let not = lsp_server::Notification::new(PublishDiagnostics::METHOD.to_string(), clear);
            connection.sender.send(Message::Notification(not))?;
        }
        Err(_not) => {
            // Unknown notification — ignored.
        }
    }

    Ok(())
}

fn publish_diagnostics(
    connection: &Connection,
    world: &WorldState,
    uri: &lsp_types::Uri,
) -> Result<(), Box<dyn std::error::Error + Sync + Send>> {
    let diagnostics = world
        .get_document(uri)
        .map(|doc| doc.diagnostics.clone())
        .unwrap_or_default();

    let params = PublishDiagnosticsParams {
        uri: uri.clone(),
        diagnostics,
        version: None,
    };

    let not = lsp_server::Notification::new(PublishDiagnostics::METHOD.to_string(), params);
    connection.sender.send(Message::Notification(not))?;
    Ok(())
}

/// Attempts to cast a request to a specific LSP request type.
/// Returns `Ok((id, params))` on success, or `Err(req)` on method mismatch.
fn cast_request<R>(req: Request) -> Result<(RequestId, R::Params), Request>
where
    R: lsp_types::request::Request,
    R::Params: serde::de::DeserializeOwned,
{
    match req.extract::<R::Params>(R::METHOD) {
        Ok(value) => Ok(value),
        Err(ExtractError::MethodMismatch(req)) => Err(req),
        Err(ExtractError::JsonError { method, error }) => {
            log::error!("Failed to deserialize {method} request: {error}");
            // Return an empty request that won't match anything.
            Err(Request {
                id: RequestId::from(0),
                method: String::new(),
                params: Value::Null,
            })
        }
    }
}

/// Attempts to cast a notification to a specific LSP notification type.
fn cast_notification<N>(not: Notification) -> Result<N::Params, Notification>
where
    N: lsp_types::notification::Notification,
    N::Params: serde::de::DeserializeOwned,
{
    match not.extract::<N::Params>(N::METHOD) {
        Ok(value) => Ok(value),
        Err(ExtractError::MethodMismatch(not)) => Err(not),
        Err(ExtractError::JsonError { method, error }) => {
            log::error!("Failed to deserialize {method} notification: {error}");
            Err(Notification {
                method: String::new(),
                params: Value::Null,
            })
        }
    }
}

fn send_response<T: serde::Serialize>(
    connection: &Connection,
    id: RequestId,
    result: Option<T>,
) -> Result<(), Box<dyn std::error::Error + Sync + Send>> {
    let result = result.map(|r| serde_json::to_value(r).unwrap());
    let resp = Response {
        id,
        result,
        error: None,
    };
    connection.sender.send(Message::Response(resp))?;
    Ok(())
}

//! Writ code generation -- produces Rust source from Writ type declarations.
//!
//! Generates struct definitions with `Deref`-based inheritance, trait
//! definitions, constructors, and `WritObject` implementations from the
//! type registry populated by `writ-types`.

mod rust_gen;
mod type_map;

pub use rust_gen::RustCodegen;
pub use type_map::{writ_type_to_rust, writ_type_to_rust_primitive};

use crate::parser::Visibility;
use crate::types::{ClassInfo, FieldInfo, MethodInfo, TraitInfo, Type, TypeRegistry};

use super::type_map::writ_type_to_rust;

/// Generates Rust source code from Writ type declarations.
///
/// Produces struct definitions with `Deref`-based inheritance, trait
/// definitions, constructor `new()` methods, and `WritObject` implementations.
pub struct RustCodegen;

impl Default for RustCodegen {
    fn default() -> Self {
        Self::new()
    }
}

impl RustCodegen {
    pub fn new() -> Self {
        Self
    }

    /// Generate Rust source for all classes and traits in the registry.
    pub fn generate(&self, registry: &TypeRegistry) -> String {
        let mut out = String::new();

        // Header
        out.push_str("// Auto-generated by writ-codegen. Do not edit.\n\n");
        out.push_str("use std::collections::HashMap;\n");
        out.push_str("use crate::vm::Value;\n");
        out.push_str("use crate::vm::WritObject;\n\n");

        // Generate traits first (classes may implement them)
        let mut trait_names: Vec<&str> = registry.trait_names().collect();
        trait_names.sort();
        for name in &trait_names {
            if let Some(info) = registry.get_trait(name) {
                out.push_str(&self.generate_trait(info));
                out.push('\n');
            }
        }

        // Generate classes in dependency order (parents before children)
        let class_order = self.topological_class_order(registry);
        for name in &class_order {
            if let Some(info) = registry.get_class(name) {
                out.push_str(&self.generate_class(info, registry));
                out.push('\n');
            }
        }

        out
    }

    /// Generate Rust source for a single trait.
    pub fn generate_trait(&self, info: &TraitInfo) -> String {
        let mut out = String::new();

        out.push_str(&format!("pub trait {} {{\n", info.name));
        for method in &info.methods {
            let params = self.format_method_params(method);
            let ret = self.format_return_type(method);

            if method.has_default_body {
                out.push_str(&format!(
                    "    fn {name}({params}){ret} {{\n",
                    name = method.name
                ));
                out.push_str("        todo!(\"default body\")\n");
                out.push_str("    }\n");
            } else {
                out.push_str(&format!(
                    "    fn {name}({params}){ret};\n",
                    name = method.name
                ));
            }
        }
        out.push_str("}\n");

        out
    }

    /// Generate Rust source for a single class.
    pub fn generate_class(&self, info: &ClassInfo, registry: &TypeRegistry) -> String {
        let mut out = String::new();

        // Struct definition
        out.push_str(&self.generate_struct_def(info));

        // Deref/DerefMut impls for inheritance
        if let Some(ref parent) = info.parent {
            out.push_str(&self.generate_deref_impls(&info.name, parent));
        }

        // Constructor
        out.push_str(&self.generate_constructor(info, registry));

        // Methods
        if !info.methods.is_empty() {
            out.push_str(&self.generate_methods(info));
        }

        // Trait impls
        for trait_name in &info.traits {
            if let Some(trait_info) = registry.get_trait(trait_name) {
                out.push_str(&self.generate_trait_impl(info, trait_info));
            }
        }

        // WritObject impl
        out.push_str(&self.generate_writ_object_impl(info, registry));

        out
    }

    fn generate_struct_def(&self, info: &ClassInfo) -> String {
        let mut out = String::new();
        out.push_str(&format!(
            "#[derive(Debug, Clone)]\npub struct {} {{\n",
            info.name
        ));

        // If extends, add a `base` field for the parent
        if let Some(ref parent) = info.parent {
            out.push_str(&format!("    base: {parent},\n"));
        }

        // Own fields only (inherited fields live in `base`)
        for field in &info.fields {
            let vis = if field.visibility == Visibility::Public {
                "pub "
            } else {
                ""
            };
            let ty = writ_type_to_rust(&field.ty);
            out.push_str(&format!("    {vis}{name}: {ty},\n", name = field.name));
        }

        out.push_str("}\n\n");
        out
    }

    fn generate_deref_impls(&self, child: &str, parent: &str) -> String {
        let mut out = String::new();

        out.push_str(&format!("impl std::ops::Deref for {child} {{\n"));
        out.push_str(&format!("    type Target = {parent};\n"));
        out.push_str(&format!(
            "    fn deref(&self) -> &{parent} {{ &self.base }}\n"
        ));
        out.push_str("}\n\n");

        out.push_str(&format!("impl std::ops::DerefMut for {child} {{\n"));
        out.push_str(&format!(
            "    fn deref_mut(&mut self) -> &mut {parent} {{ &mut self.base }}\n"
        ));
        out.push_str("}\n\n");

        out
    }

    fn generate_constructor(&self, info: &ClassInfo, registry: &TypeRegistry) -> String {
        let mut out = String::new();

        // Collect all fields in order: parent chain fields first, then own
        let all_fields = registry.all_fields(&info.name);

        out.push_str(&format!("impl {} {{\n", info.name));
        out.push_str("    pub fn new(");

        // Constructor params = all fields in order
        let params: Vec<String> = all_fields
            .iter()
            .map(|f| format!("{}: {}", f.name, writ_type_to_rust(&f.ty)))
            .collect();
        out.push_str(&params.join(", "));
        out.push_str(") -> Self {\n");

        if let Some(ref parent) = info.parent {
            // Separate parent fields from own fields
            let parent_fields = self.collect_parent_fields(info, registry);
            let parent_args: Vec<String> = parent_fields.iter().map(|f| f.name.clone()).collect();

            out.push_str("        Self {\n");
            out.push_str(&format!(
                "            base: {parent}::new({}),\n",
                parent_args.join(", ")
            ));

            for field in &info.fields {
                out.push_str(&format!("            {name}: {name},\n", name = field.name));
            }
            out.push_str("        }\n");
        } else {
            out.push_str("        Self {\n");
            for field in &info.fields {
                out.push_str(&format!("            {name}: {name},\n", name = field.name));
            }
            out.push_str("        }\n");
        }

        out.push_str("    }\n");
        out.push_str("}\n\n");
        out
    }

    fn generate_methods(&self, info: &ClassInfo) -> String {
        let mut out = String::new();
        out.push_str(&format!("impl {} {{\n", info.name));

        for method in &info.methods {
            let vis = if method.visibility == Visibility::Public {
                "pub "
            } else {
                ""
            };
            let params = self.format_method_params(method);
            let ret = self.format_return_type(method);

            out.push_str(&format!(
                "    {vis}fn {name}({params}){ret} {{\n",
                name = method.name
            ));
            out.push_str("        todo!(\"method body\")\n");
            out.push_str("    }\n");
        }

        out.push_str("}\n\n");
        out
    }

    fn generate_trait_impl(&self, class: &ClassInfo, trait_info: &TraitInfo) -> String {
        let mut out = String::new();
        out.push_str(&format!("impl {} for {} {{\n", trait_info.name, class.name));

        // Find class methods that match trait methods
        for trait_method in &trait_info.methods {
            let params = self.format_method_params(trait_method);
            let ret = self.format_return_type(trait_method);

            // Check if the class has an implementation
            let has_impl = class.methods.iter().any(|m| m.name == trait_method.name);

            if has_impl {
                out.push_str(&format!(
                    "    fn {name}({params}){ret} {{\n",
                    name = trait_method.name
                ));
                out.push_str("        todo!(\"trait method body\")\n");
                out.push_str("    }\n");
            } else if !trait_method.has_default_body {
                // Required method not implemented -- emit a stub
                out.push_str(&format!(
                    "    fn {name}({params}){ret} {{\n",
                    name = trait_method.name
                ));
                out.push_str("        unimplemented!(\"required trait method\")\n");
                out.push_str("    }\n");
            }
            // Methods with default bodies are inherited, no need to emit
        }

        out.push_str("}\n\n");
        out
    }

    fn generate_writ_object_impl(&self, info: &ClassInfo, registry: &TypeRegistry) -> String {
        let mut out = String::new();

        out.push_str(&format!("impl WritObject for {} {{\n", info.name));

        // type_name()
        out.push_str(&format!(
            "    fn type_name(&self) -> &str {{ \"{}\" }}\n\n",
            info.name
        ));

        // get_field()
        let all_fields = registry.all_fields(&info.name);
        out.push_str("    fn get_field(&self, name: &str) -> Result<Value, String> {\n");
        out.push_str("        match name {\n");
        for field in &all_fields {
            out.push_str(&format!(
                "            \"{name}\" => Ok(self.{name}.clone().into()),\n",
                name = field.name
            ));
        }
        out.push_str(&format!(
            "            _ => Err(format!(\"'{}' has no field '{{}}'\", name)),\n",
            info.name
        ));
        out.push_str("        }\n");
        out.push_str("    }\n\n");

        // set_field()
        out.push_str(
            "    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {\n",
        );
        out.push_str("        match name {\n");
        for field in &all_fields {
            out.push_str(&format!(
                "            \"{name}\" => {{ self.{name} = value.try_into().map_err(|e: String| e)?; Ok(()) }}\n",
                name = field.name
            ));
        }
        out.push_str(&format!(
            "            _ => Err(format!(\"'{}' has no field '{{}}'\", name)),\n",
            info.name
        ));
        out.push_str("        }\n");
        out.push_str("    }\n\n");

        // call_method()
        out.push_str(
            "    fn call_method(&mut self, name: &str, _args: &[Value]) -> Result<Value, String> {\n",
        );
        out.push_str(&format!(
            "        Err(format!(\"'{}' has no native method '{{}}'\", name))\n",
            info.name
        ));
        out.push_str("    }\n\n");

        // as_any()
        out.push_str("    fn as_any(&self) -> &dyn std::any::Any {\n");
        out.push_str("        self\n");
        out.push_str("    }\n");

        out.push_str("}\n\n");
        out
    }

    fn format_method_params(&self, method: &MethodInfo) -> String {
        let mut parts = vec!["&mut self".to_string()];
        for (i, ty) in method.params.iter().enumerate() {
            parts.push(format!("arg{i}: {}", writ_type_to_rust(ty)));
        }
        parts.join(", ")
    }

    fn format_return_type(&self, method: &MethodInfo) -> String {
        if method.return_type == Type::Void {
            String::new()
        } else {
            format!(" -> {}", writ_type_to_rust(&method.return_type))
        }
    }

    fn collect_parent_fields(&self, info: &ClassInfo, registry: &TypeRegistry) -> Vec<FieldInfo> {
        let all = registry.all_fields(&info.name);
        let own_names: std::collections::HashSet<&str> =
            info.fields.iter().map(|f| f.name.as_str()).collect();
        all.into_iter()
            .filter(|f| !own_names.contains(f.name.as_str()))
            .collect()
    }

    /// Returns class names in topological order (parents before children).
    fn topological_class_order(&self, registry: &TypeRegistry) -> Vec<String> {
        let mut names: Vec<String> = registry.class_names().map(|s| s.to_string()).collect();
        names.sort();

        let mut ordered = Vec::new();
        let mut visited = std::collections::HashSet::new();

        for name in &names {
            self.topo_visit(name, registry, &mut ordered, &mut visited);
        }

        ordered
    }

    fn topo_visit(
        &self,
        name: &str,
        registry: &TypeRegistry,
        ordered: &mut Vec<String>,
        visited: &mut std::collections::HashSet<String>,
    ) {
        if visited.contains(name) {
            return;
        }
        visited.insert(name.to_string());

        // Visit parent first
        if let Some(info) = registry.get_class(name)
            && let Some(ref parent) = info.parent
        {
            self.topo_visit(parent, registry, ordered, visited);
        }

        ordered.push(name.to_string());
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::parser::Visibility;
    use crate::types::{ClassInfo, FieldInfo, MethodInfo, TraitInfo, TypeRegistry};

    fn make_registry() -> TypeRegistry {
        let mut reg = TypeRegistry::new();

        // Register Entity (base class)
        reg.register_class(ClassInfo {
            name: "Entity".to_string(),
            fields: vec![
                FieldInfo {
                    name: "x".to_string(),
                    ty: Type::Float,
                    visibility: Visibility::Public,
                    has_default: true,
                    has_setter: false,
                },
                FieldInfo {
                    name: "y".to_string(),
                    ty: Type::Float,
                    visibility: Visibility::Public,
                    has_default: true,
                    has_setter: false,
                },
            ],
            methods: vec![],
            parent: None,
            traits: vec![],
        });

        // Register Player (extends Entity)
        reg.register_class(ClassInfo {
            name: "Player".to_string(),
            fields: vec![FieldInfo {
                name: "health".to_string(),
                ty: Type::Float,
                visibility: Visibility::Public,
                has_default: true,
                has_setter: false,
            }],
            methods: vec![MethodInfo {
                name: "takeDamage".to_string(),
                params: vec![Type::Float],
                return_type: Type::Void,
                is_static: false,
                visibility: Visibility::Public,
                has_default_body: false,
            }],
            parent: Some("Entity".to_string()),
            traits: vec![],
        });

        reg
    }

    #[test]
    fn generates_struct_with_deref() {
        let codegen = RustCodegen::new();
        let registry = make_registry();
        let output = codegen.generate(&registry);

        // Entity struct should be generated
        assert!(output.contains("pub struct Entity {"));
        assert!(output.contains("pub x: f32"));
        assert!(output.contains("pub y: f32"));

        // Player struct should have base field
        assert!(output.contains("pub struct Player {"));
        assert!(output.contains("base: Entity,"));
        assert!(output.contains("pub health: f32"));

        // Deref impls
        assert!(output.contains("impl std::ops::Deref for Player"));
        assert!(output.contains("type Target = Entity"));
        assert!(output.contains("impl std::ops::DerefMut for Player"));
    }

    #[test]
    fn generates_constructor() {
        let codegen = RustCodegen::new();
        let registry = make_registry();
        let output = codegen.generate(&registry);

        // Entity constructor
        assert!(output.contains("impl Entity {"));
        assert!(output.contains("pub fn new(x: f32, y: f32) -> Self"));

        // Player constructor takes parent fields + own fields
        assert!(output.contains("pub fn new(x: f32, y: f32, health: f32) -> Self"));
        assert!(output.contains("base: Entity::new(x, y)"));
    }

    #[test]
    fn generates_writ_object_impl() {
        let codegen = RustCodegen::new();
        let registry = make_registry();
        let output = codegen.generate(&registry);

        assert!(output.contains("impl WritObject for Entity"));
        assert!(output.contains("impl WritObject for Player"));
        assert!(output.contains("fn type_name(&self) -> &str { \"Player\" }"));
    }

    #[test]
    fn topological_order_parents_first() {
        let codegen = RustCodegen::new();
        let registry = make_registry();
        let order = codegen.topological_class_order(&registry);

        let entity_pos = order.iter().position(|n| n == "Entity").unwrap();
        let player_pos = order.iter().position(|n| n == "Player").unwrap();
        assert!(entity_pos < player_pos, "Entity should come before Player");
    }

    #[test]
    fn trait_codegen() {
        let mut reg = TypeRegistry::new();
        reg.register_trait(TraitInfo {
            name: "Damageable".to_string(),
            methods: vec![
                MethodInfo {
                    name: "takeDamage".to_string(),
                    params: vec![Type::Float],
                    return_type: Type::Void,
                    is_static: false,
                    visibility: Visibility::Public,
                    has_default_body: false,
                },
                MethodInfo {
                    name: "die".to_string(),
                    params: vec![],
                    return_type: Type::Void,
                    is_static: false,
                    visibility: Visibility::Public,
                    has_default_body: true,
                },
            ],
        });

        let codegen = RustCodegen::new();
        let output = codegen.generate(&reg);

        assert!(output.contains("pub trait Damageable {"));
        assert!(output.contains("fn takeDamage(&mut self, arg0: f32);"));
        assert!(output.contains("fn die(&mut self) {"));
    }
}

use crate::types::Type;

/// Maps a Writ type to its Rust type string representation.
///
/// Since the VM's `Value` enum uses flat variants (`I32`/`I64`/`F32`/`F64`),
/// generated code uses `i32`/`f32` as the default narrow types. Width promotion
/// happens at the VM level when arithmetic overflows.
pub fn writ_type_to_rust(ty: &Type) -> String {
    match ty {
        Type::Int => "i32".to_string(),
        Type::Float => "f32".to_string(),
        Type::Bool => "bool".to_string(),
        Type::Str => "String".to_string(),
        Type::Void => "()".to_string(),
        Type::Unknown => "Value".to_string(),
        Type::Array(inner) => format!("Vec<{}>", writ_type_to_rust(inner)),
        Type::Dictionary(k, v) => {
            format!(
                "HashMap<{}, {}>",
                writ_type_to_rust(k),
                writ_type_to_rust(v)
            )
        }
        Type::Optional(inner) => format!("Option<{}>", writ_type_to_rust(inner)),
        Type::Result(inner) => format!("Result<{}, String>", writ_type_to_rust(inner)),
        Type::Tuple(types) => {
            let parts: Vec<String> = types.iter().map(writ_type_to_rust).collect();
            format!("({})", parts.join(", "))
        }
        Type::Class(name) => name.clone(),
        Type::Trait(name) => format!("Box<dyn {name}>"),
        Type::Function {
            params,
            return_type,
        } => {
            let param_types: Vec<String> = params.iter().map(writ_type_to_rust).collect();
            let ret = writ_type_to_rust(return_type);
            format!("Box<dyn Fn({}) -> {}>", param_types.join(", "), ret)
        }
        Type::Enum(name) => name.clone(),
        Type::Struct(name) => name.clone(),
    }
}

/// Maps a Writ type to a Rust type string using primitive types (i32/f32).
/// Now identical to `writ_type_to_rust` since the VM uses flat primitives.
pub fn writ_type_to_rust_primitive(ty: &Type) -> String {
    writ_type_to_rust(ty)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn primitives() {
        assert_eq!(writ_type_to_rust(&Type::Int), "i32");
        assert_eq!(writ_type_to_rust(&Type::Float), "f32");
        assert_eq!(writ_type_to_rust(&Type::Bool), "bool");
        assert_eq!(writ_type_to_rust(&Type::Str), "String");
        assert_eq!(writ_type_to_rust(&Type::Void), "()");
    }

    #[test]
    fn collections() {
        assert_eq!(
            writ_type_to_rust(&Type::Array(Box::new(Type::Int))),
            "Vec<i32>"
        );
        assert_eq!(
            writ_type_to_rust(&Type::Dictionary(Box::new(Type::Str), Box::new(Type::Int))),
            "HashMap<String, i32>"
        );
    }

    #[test]
    fn optional_and_result() {
        assert_eq!(
            writ_type_to_rust(&Type::Optional(Box::new(Type::Str))),
            "Option<String>"
        );
        assert_eq!(
            writ_type_to_rust(&Type::Result(Box::new(Type::Int))),
            "Result<i32, String>"
        );
    }

    #[test]
    fn class_type() {
        assert_eq!(
            writ_type_to_rust(&Type::Class("Player".to_string())),
