        );
    }

    #[test]
    fn primitives_mode() {
        assert_eq!(writ_type_to_rust_primitive(&Type::Int), "i32");
        assert_eq!(writ_type_to_rust_primitive(&Type::Float), "f32");
        assert_eq!(writ_type_to_rust_primitive(&Type::Bool), "bool");
    }
