    pub const DivInt: u8 = 20;
    pub const DivFloat: u8 = 21;

    // --- Arithmetic immediate (22-23) ---
    pub const AddIntImm: u8 = 22; // AB+W: dst, src, i32
    pub const SubIntImm: u8 = 23; // AB+W: dst, src, i32

    // --- Type coercion (24) ---
    pub const IntToFloat: u8 = 24; // AB: dst, src

