use std::cell::RefCell;
use std::rc::Rc;

use crate::vm::{VM, Value, WritObject};

use super::vector::extract_f32;

#[derive(Debug, Clone)]
pub struct WritColor {
    pub r: f32,
    pub g: f32,
    pub b: f32,
    pub a: f32,
}

impl WritObject for WritColor {
    fn type_name(&self) -> &str {
        "Color"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "r" => Ok(Value::F64(self.r as f64)),
            "g" => Ok(Value::F64(self.g as f64)),
            "b" => Ok(Value::F64(self.b as f64)),
            "a" => Ok(Value::F64(self.a as f64)),
            _ => Err(format!("Color has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {
        let f = extract_f32(&value, name)?;
        match name {
            "r" => self.r = f,
            "g" => self.g = f,
            "b" => self.b = f,
            "a" => self.a = f,
            _ => return Err(format!("Color has no field '{name}'")),
        }
        Ok(())
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            "toHex" => {
                let r = (self.r.clamp(0.0, 1.0) * 255.0) as u8;
                let g = (self.g.clamp(0.0, 1.0) * 255.0) as u8;
                let b = (self.b.clamp(0.0, 1.0) * 255.0) as u8;
                let a = (self.a.clamp(0.0, 1.0) * 255.0) as u8;
                if a == 255 {
                    Ok(Value::Str(Rc::from(
                        format!("#{r:02X}{g:02X}{b:02X}").as_str(),
                    )))
                } else {
                    Ok(Value::Str(Rc::from(
                        format!("#{r:02X}{g:02X}{b:02X}{a:02X}").as_str(),
                    )))
                }
            }
            "toHSV" => {
                let (h, s, v) = rgb_to_hsv(self.r, self.g, self.b);
                let arr = vec![
                    Value::F64(h as f64),
                    Value::F64(s as f64),
                    Value::F64(v as f64),
                ];
                Ok(Value::Array(Rc::new(RefCell::new(arr))))
            }
            "lerp" => {
                let other = extract_color(args, 0)?;
                let t = extract_f32(args.get(1).ok_or("missing argument 't'")?, "t")?;
                Ok(color_value(WritColor {
                    r: self.r + (other.r - self.r) * t,
                    g: self.g + (other.g - self.g) * t,
                    b: self.b + (other.b - self.b) * t,
                    a: self.a + (other.a - self.a) * t,
                }))
            }
            "lighten" => {
                let amount = extract_f32(args.first().ok_or("missing amount argument")?, "amount")?;
                Ok(color_value(WritColor {
                    r: (self.r + amount).min(1.0),
                    g: (self.g + amount).min(1.0),
                    b: (self.b + amount).min(1.0),
                    a: self.a,
                }))
            }
            "darken" => {
                let amount = extract_f32(args.first().ok_or("missing amount argument")?, "amount")?;
                Ok(color_value(WritColor {
                    r: (self.r - amount).max(0.0),
                    g: (self.g - amount).max(0.0),
                    b: (self.b - amount).max(0.0),
                    a: self.a,
                }))
            }
            "inverted" => Ok(color_value(WritColor {
                r: 1.0 - self.r,
                g: 1.0 - self.g,
                b: 1.0 - self.b,
                a: self.a,
            })),
            "withAlpha" => {
                let a = extract_f32(args.first().ok_or("missing alpha argument")?, "alpha")?;
                Ok(color_value(WritColor {
                    r: self.r,
                    g: self.g,
                    b: self.b,
                    a,
                }))
            }
            _ => Err(format!("Color has no method '{name}'")),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

// --- Helpers ---

fn color_value(c: WritColor) -> Value {
    Value::Object(Rc::new(RefCell::new(c)))
}

fn extract_color(args: &[Value], idx: usize) -> Result<WritColor, String> {
    let v = args.get(idx).ok_or("missing Color argument")?;
    match v {
        Value::Object(obj) => {
            let b = obj.borrow();
            b.as_any()
                .downcast_ref::<WritColor>()
                .cloned()
                .ok_or_else(|| format!("expected Color, got {}", b.type_name()))
        }
        other => Err(format!("expected Color, got {}", other.type_name())),
    }
}

fn rgb_to_hsv(r: f32, g: f32, b: f32) -> (f32, f32, f32) {
    let max = r.max(g).max(b);
    let min = r.min(g).min(b);
    let delta = max - min;

    let h = if delta == 0.0 {
        0.0
    } else if max == r {
        60.0 * (((g - b) / delta) % 6.0)
    } else if max == g {
        60.0 * (((b - r) / delta) + 2.0)
    } else {
        60.0 * (((r - g) / delta) + 4.0)
    };

    let s = if max == 0.0 { 0.0 } else { delta / max };
    (if h < 0.0 { h + 360.0 } else { h }, s, max)
}

fn hsv_to_rgb(h: f32, s: f32, v: f32) -> (f32, f32, f32) {
    let c = v * s;
    let x = c * (1.0 - ((h / 60.0) % 2.0 - 1.0).abs());
    let m = v - c;
    let (r, g, b) = if h < 60.0 {
        (c, x, 0.0)
    } else if h < 120.0 {
        (x, c, 0.0)
    } else if h < 180.0 {
        (0.0, c, x)
    } else if h < 240.0 {
        (0.0, x, c)
    } else if h < 300.0 {
        (x, 0.0, c)
    } else {
        (c, 0.0, x)
    };
    (r + m, g + m, b + m)
}

fn parse_hex(s: &str) -> Result<WritColor, String> {
    let s = s.trim_start_matches('#');
    match s.len() {
        6 => {
            let r = u8::from_str_radix(&s[0..2], 16).map_err(|e| e.to_string())? as f32 / 255.0;
            let g = u8::from_str_radix(&s[2..4], 16).map_err(|e| e.to_string())? as f32 / 255.0;
            let b = u8::from_str_radix(&s[4..6], 16).map_err(|e| e.to_string())? as f32 / 255.0;
            Ok(WritColor { r, g, b, a: 1.0 })
        }
        8 => {
            let r = u8::from_str_radix(&s[0..2], 16).map_err(|e| e.to_string())? as f32 / 255.0;
            let g = u8::from_str_radix(&s[2..4], 16).map_err(|e| e.to_string())? as f32 / 255.0;
            let b = u8::from_str_radix(&s[4..6], 16).map_err(|e| e.to_string())? as f32 / 255.0;
            let a = u8::from_str_radix(&s[6..8], 16).map_err(|e| e.to_string())? as f32 / 255.0;
            Ok(WritColor { r, g, b, a })
        }
        _ => Err(format!("invalid hex color: #{s}")),
    }
}

// --- Registration ---

pub fn register(vm: &mut VM) {
    // Color(r, g, b) or Color(r, g, b, a)
    vm.register_type("Color", |args| {
        let r = extract_f32(args.first().ok_or("Color: missing r")?, "r")?;
        let g = extract_f32(args.get(1).ok_or("Color: missing g")?, "g")?;
        let b = extract_f32(args.get(2).ok_or("Color: missing b")?, "b")?;
        let a = args
            .get(3)
            .map(|v| extract_f32(v, "a"))
            .transpose()?
            .unwrap_or(1.0);
        Ok(Box::new(WritColor { r, g, b, a }))
    });

    // Color.fromHex
    vm.register_fn_in_module(
        "Color_fromHex",
        "color",
        crate::vm::binding::fn1(|hex: String| -> Result<Value, String> {
            let c = parse_hex(&hex)?;
            Ok(color_value(c))
        }),
    );

    // Color.fromHSV
    vm.register_fn_in_module(
        "Color_fromHSV",
        "color",
        crate::vm::binding::fn3(|h: f64, s: f64, v: f64| -> Result<Value, String> {
            let (r, g, b) = hsv_to_rgb(h as f32, s as f32, v as f32);
            Ok(color_value(WritColor { r, g, b, a: 1.0 }))
        }),
    );

    // Constants
    vm.register_global(
        "Color_WHITE",
        color_value(WritColor {
            r: 1.0,
            g: 1.0,
            b: 1.0,
            a: 1.0,
        }),
    );
    vm.register_global(
        "Color_BLACK",
        color_value(WritColor {
            r: 0.0,
            g: 0.0,
            b: 0.0,
            a: 1.0,
        }),
    );
    vm.register_global(
        "Color_RED",
        color_value(WritColor {
            r: 1.0,
            g: 0.0,
            b: 0.0,
            a: 1.0,
        }),
    );
    vm.register_global(
        "Color_GREEN",
        color_value(WritColor {
            r: 0.0,
            g: 1.0,
            b: 0.0,
            a: 1.0,
        }),
    );
    vm.register_global(
        "Color_BLUE",
        color_value(WritColor {
            r: 0.0,
            g: 0.0,
            b: 1.0,
            a: 1.0,
        }),
    );
    vm.register_global(
        "Color_YELLOW",
        color_value(WritColor {
            r: 1.0,
            g: 1.0,
            b: 0.0,
            a: 1.0,
        }),
    );
    vm.register_global(
        "Color_CYAN",
        color_value(WritColor {
            r: 0.0,
            g: 1.0,
            b: 1.0,
            a: 1.0,
        }),
    );
    vm.register_global(
        "Color_MAGENTA",
        color_value(WritColor {
            r: 1.0,
            g: 0.0,
            b: 1.0,
            a: 1.0,
        }),
    );
    vm.register_global(
        "Color_TRANSPARENT",
        color_value(WritColor {
            r: 0.0,
            g: 0.0,
            b: 0.0,
            a: 0.0,
        }),
    );
}

use std::cell::RefCell;
use std::collections::HashMap;
use std::rc::Rc;

use crate::vm::binding::{mfn0, mfn1};
use crate::vm::{VM, Value, ValueTag};

type Dict = Rc<RefCell<HashMap<String, Value>>>;

pub fn register(vm: &mut VM) {
    vm.register_method(
        ValueTag::Dict,
        "keys",
        Some("dictionary"),
        mfn0(|dict: Dict| -> Result<Value, String> {
            let keys: Vec<Value> = dict
                .borrow()
                .keys()
                .map(|k| Value::Str(Rc::from(k.as_str())))
                .collect();
            Ok(Value::Array(Rc::new(RefCell::new(keys))))
        }),
    );

    vm.register_method(
        ValueTag::Dict,
        "values",
        Some("dictionary"),
        mfn0(|dict: Dict| -> Result<Value, String> {
            let values: Vec<Value> = dict.borrow().values().cloned().collect();
            Ok(Value::Array(Rc::new(RefCell::new(values))))
        }),
    );

    vm.register_method(
        ValueTag::Dict,
        "has",
        Some("dictionary"),
        mfn1(|dict: Dict, key: Rc<str>| -> Result<bool, String> {
            Ok(dict.borrow().contains_key(&*key))
        }),
    );

    vm.register_method(
        ValueTag::Dict,
        "remove",
        Some("dictionary"),
        mfn1(|dict: Dict, key: Rc<str>| -> Result<Value, String> {
            Ok(dict.borrow_mut().remove(&*key).unwrap_or(Value::Null))
        }),
    );

    vm.register_method(
        ValueTag::Dict,
        "len",
        Some("dictionary"),
        mfn0(|dict: Dict| -> Result<i32, String> { Ok(dict.borrow().len() as i32) }),
    );

    vm.register_method(
        ValueTag::Dict,
        "isEmpty",
        Some("dictionary"),
        mfn0(|dict: Dict| -> Result<bool, String> { Ok(dict.borrow().is_empty()) }),
    );

    vm.register_method(
        ValueTag::Dict,
        "merge",
        Some("dictionary"),
        mfn1(|dict: Dict, other: Dict| -> Result<(), String> {
            let other_entries = other.borrow();
            let mut target = dict.borrow_mut();
            for (k, v) in other_entries.iter() {
                target.insert(k.clone(), v.clone());
            }
            Ok(())
        }),
    );
}

use std::f64::consts::PI;

use crate::vm::binding::{fn1, fn3};
use crate::vm::{VM, Value};

use super::vector::extract_f64;

pub fn register(vm: &mut VM) {
    // --- Core interpolation ---

    vm.register_fn_in_module(
        "lerp",
        "interpolation",
        fn3(|a: f64, b: f64, t: f64| -> Result<f64, String> { Ok(a + (b - a) * t) }),
    );

    vm.register_fn_in_module(
        "inverseLerp",
        "interpolation",
        fn3(|a: f64, b: f64, value: f64| -> Result<f64, String> {
            if (b - a).abs() < f64::EPSILON {
                return Ok(0.0);
            }
            Ok((value - a) / (b - a))
        }),
    );

    vm.register_fn_in_module(
        "remap",
        "interpolation",
        super::matrix::RawFn(std::rc::Rc::new(|args: &[Value]| {
            let value = extract_f64(args.first().ok_or("missing value")?, "value")?;
            let from_min = extract_f64(args.get(1).ok_or("missing fromMin")?, "fromMin")?;
            let from_max = extract_f64(args.get(2).ok_or("missing fromMax")?, "fromMax")?;
            let to_min = extract_f64(args.get(3).ok_or("missing toMin")?, "toMin")?;
            let to_max = extract_f64(args.get(4).ok_or("missing toMax")?, "toMax")?;
            let t = (value - from_min) / (from_max - from_min);
            Ok(Value::F64(to_min + (to_max - to_min) * t))
        })),
    );

    vm.register_fn_in_module(
        "smoothstep",
        "interpolation",
        fn3(|a: f64, b: f64, t: f64| -> Result<f64, String> {
            let t = ((t - a) / (b - a)).clamp(0.0, 1.0);
            Ok(t * t * (3.0 - 2.0 * t))
        }),
    );

    vm.register_fn_in_module(
        "smootherstep",
        "interpolation",
        fn3(|a: f64, b: f64, t: f64| -> Result<f64, String> {
            let t = ((t - a) / (b - a)).clamp(0.0, 1.0);
            Ok(t * t * t * (t * (t * 6.0 - 15.0) + 10.0))
        }),
    );

    // --- Easing functions ---

    vm.register_fn_in_module(
        "easeInSine",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok(1.0 - (t * PI / 2.0).cos()) }),
    );
    vm.register_fn_in_module(
        "easeOutSine",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok((t * PI / 2.0).sin()) }),
    );
    vm.register_fn_in_module(
        "easeInOutSine",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok(-(PI * t).cos() / 2.0 + 0.5) }),
    );

    vm.register_fn_in_module(
        "easeInQuad",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok(t * t) }),
    );
    vm.register_fn_in_module(
        "easeOutQuad",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok(1.0 - (1.0 - t) * (1.0 - t)) }),
    );
    vm.register_fn_in_module(
        "easeInOutQuad",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> {
            Ok(if t < 0.5 {
                2.0 * t * t
            } else {
                1.0 - (-2.0 * t + 2.0).powi(2) / 2.0
            })
        }),
    );

    vm.register_fn_in_module(
        "easeInCubic",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok(t * t * t) }),
    );
    vm.register_fn_in_module(
        "easeOutCubic",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok(1.0 - (1.0 - t).powi(3)) }),
    );
    vm.register_fn_in_module(
        "easeInOutCubic",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> {
            Ok(if t < 0.5 {
                4.0 * t * t * t
            } else {
                1.0 - (-2.0 * t + 2.0).powi(3) / 2.0
            })
        }),
    );

    vm.register_fn_in_module(
        "easeInExpo",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> {
            Ok(if t == 0.0 {
                0.0
            } else {
                (2.0_f64).powf(10.0 * t - 10.0)
            })
        }),
    );
    vm.register_fn_in_module(
        "easeOutExpo",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> {
            Ok(if t == 1.0 {
                1.0
            } else {
                1.0 - (2.0_f64).powf(-10.0 * t)
            })
        }),
    );
    vm.register_fn_in_module(
        "easeInOutExpo",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> {
            Ok(if t == 0.0 {
                0.0
            } else if t == 1.0 {
                1.0
            } else if t < 0.5 {
                (2.0_f64).powf(20.0 * t - 10.0) / 2.0
            } else {
                (2.0 - (2.0_f64).powf(-20.0 * t + 10.0)) / 2.0
            })
        }),
    );

    vm.register_fn_in_module(
        "easeInElastic",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> {
            let c4 = (2.0 * PI) / 3.0;
            Ok(if t == 0.0 {
                0.0
            } else if t == 1.0 {
                1.0
            } else {
                -(2.0_f64).powf(10.0 * t - 10.0) * ((10.0 * t - 10.75) * c4).sin()
            })
        }),
    );
    vm.register_fn_in_module(
        "easeOutElastic",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> {
            let c4 = (2.0 * PI) / 3.0;
            Ok(if t == 0.0 {
                0.0
            } else if t == 1.0 {
                1.0
            } else {
                (2.0_f64).powf(-10.0 * t) * ((10.0 * t - 0.75) * c4).sin() + 1.0
            })
        }),
    );

    vm.register_fn_in_module(
        "easeInBounce",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok(1.0 - bounce_out(1.0 - t)) }),
    );
    vm.register_fn_in_module(
        "easeOutBounce",
        "interpolation",
        fn1(|t: f64| -> Result<f64, String> { Ok(bounce_out(t)) }),
    );
}

fn bounce_out(t: f64) -> f64 {
    let n1 = 7.5625;
    let d1 = 2.75;
    if t < 1.0 / d1 {
        n1 * t * t
    } else if t < 2.0 / d1 {
        let t = t - 1.5 / d1;
        n1 * t * t + 0.75
    } else if t < 2.5 / d1 {
        let t = t - 2.25 / d1;
        n1 * t * t + 0.9375
    } else {
        let t = t - 2.625 / d1;
        n1 * t * t + 0.984375
    }
}

use std::rc::Rc;

use crate::vm::binding::{fn0, fn1, fn2};
use crate::vm::{VM, Value};

pub fn register(vm: &mut VM) {
    vm.register_fn_in_module(
        "readFile",
        "io",
        fn1(|path: String| -> Result<String, String> {
            std::fs::read_to_string(&path).map_err(|e| format!("readFile failed: {e}"))
        }),
    );

    vm.register_fn_in_module(
        "writeFile",
        "io",
        fn2(|path: String, content: String| -> Result<(), String> {
            std::fs::write(&path, &content).map_err(|e| format!("writeFile failed: {e}"))
        }),
    );

    vm.register_fn_in_module(
        "readLine",
        "io",
        fn0(|| -> Result<Value, String> {
            let mut line = String::new();
            std::io::stdin()
                .read_line(&mut line)
                .map_err(|e| format!("readLine failed: {e}"))?;
            if line.ends_with('\n') {
                line.pop();
                if line.ends_with('\r') {
                    line.pop();
                }
            }
            Ok(Value::Str(Rc::from(line.as_str())))
        }),
    );

    vm.register_fn_in_module(
        "fileExists",
        "io",
        fn1(|path: String| -> Result<bool, String> { Ok(std::path::Path::new(&path).exists()) }),
    );
}

