/// Registers all standard library modules except the ones listed in `excluded`.
///
/// Module names: `"basic"`, `"math"`, `"string"`, `"array"`, `"dictionary"`,
/// `"io"`, `"time"`, `"random"`, `"reflection"`, `"vector"`, `"matrix"`,
/// `"quaternion"`, `"transform"`, `"rectangle"`, `"color"`, `"interpolation"`,
/// `"noise"`, `"tween"`, `"timer"`, `"input"`, `"regex"`.
pub fn register_except(vm: &mut VM, excluded: &[&str]) {
    type ModuleEntry = (&'static str, fn(&mut VM));
    let modules: &[ModuleEntry] = &[
        ("basic", basic::register),
        ("math", math::register),
        ("string", string::register),
        ("array", array::register),
        ("dictionary", dict::register),
        ("io", io::register),
        ("time", time::register),
        ("random", random::register),
        ("reflection", reflect::register),
        ("vector", vector::register),
        ("matrix", matrix::register),
        ("quaternion", quaternion::register),
        ("transform", transform::register),
        ("rectangle", rect::register),
        ("color", color::register),
        ("interpolation", interpolation::register),
        ("noise", noise::register),
        ("tween", tween::register),
        ("timer", timer::register),
        ("input", input::register),
        ("regex", regex::register),
    ];
    for (name, register_fn) in modules {
        if !excluded.contains(name) {
            register_fn(vm);
        }
    }
}

use std::cell::RefCell;

use crate::vm::binding::{fn1, fn2, fn3};
use crate::vm::{VM, Value};
use fastnoise_lite::{FastNoiseLite, FractalType, NoiseType};

thread_local! {
    static NOISE: RefCell<FastNoiseLite> = RefCell::new(FastNoiseLite::new());
}

fn with_noise<F, R>(f: F) -> R
where
    F: FnOnce(&FastNoiseLite) -> R,
{
    NOISE.with(|n| f(&n.borrow()))
}

fn with_noise_mut<F, R>(f: F) -> R
where
    F: FnOnce(&mut FastNoiseLite) -> R,
{
    NOISE.with(|n| f(&mut n.borrow_mut()))
}

pub fn register(vm: &mut VM) {
    vm.register_fn_in_module(
        "noise2D",
        "noise",
        fn2(|x: f64, y: f64| -> Result<f64, String> {
            Ok(with_noise(|n| n.get_noise_2d(x as f32, y as f32)) as f64)
        }),
    );

    vm.register_fn_in_module(
        "noise3D",
        "noise",
        fn3(|x: f64, y: f64, z: f64| -> Result<f64, String> {
            Ok(with_noise(|n| n.get_noise_3d(x as f32, y as f32, z as f32)) as f64)
        }),
    );

    vm.register_fn_in_module(
        "noiseSeed",
        "noise",
        fn1(|seed: f64| -> Result<f64, String> {
            with_noise_mut(|n| n.set_seed(Some(seed as i32)));
            Ok(0.0)
        }),
    );

    vm.register_fn_in_module(
        "noiseType",
        "noise",
        super::matrix::RawFn(std::rc::Rc::new(|args: &[Value]| {
            let name = match args.first().ok_or("missing type")? {
                Value::Str(s) => s.clone(),
                other => return Err(format!("noiseType expects string, got {:?}", other)),
            };
            let nt = match &*name {
                "perlin" => NoiseType::Perlin,
                "simplex" | "openSimplex2" => NoiseType::OpenSimplex2,
                "openSimplex2S" => NoiseType::OpenSimplex2S,
                "cellular" | "voronoi" => NoiseType::Cellular,
                "value" => NoiseType::Value,
                "valueCubic" => NoiseType::ValueCubic,
                _ => return Err(format!("unknown noise type: {}", name)),
            };
            with_noise_mut(|n| n.set_noise_type(Some(nt)));
            Ok(Value::F64(0.0))
        })),
    );

    vm.register_fn_in_module(
        "noiseFractal",
        "noise",
        fn3(
            |octaves: f64, lacunarity: f64, gain: f64| -> Result<f64, String> {
                with_noise_mut(|n| {
                    n.set_fractal_type(Some(FractalType::FBm));
                    n.set_fractal_octaves(Some(octaves as i32));
                    n.set_fractal_lacunarity(Some(lacunarity as f32));
                    n.set_fractal_gain(Some(gain as f32));
                });
                Ok(0.0)
            },
        ),
    );

    vm.register_fn_in_module(
        "noiseFrequency",
        "noise",
        fn1(|freq: f64| -> Result<f64, String> {
            with_noise_mut(|n| n.set_frequency(Some(freq as f32)));
            Ok(0.0)
        }),
    );
}

use std::cell::RefCell;
use std::rc::Rc;

use crate::vm::{VM, Value, WritObject};
use glam::Quat;

use super::matrix::mat4_value;
use super::vector::{extract_f32, extract_vec3, value_to_vec3, vec3_value};

#[derive(Debug, Clone)]
pub struct WritQuaternion(pub Quat);

impl WritObject for WritQuaternion {
    fn type_name(&self) -> &str {
        "Quaternion"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "x" => Ok(Value::F64(self.0.x as f64)),
            "y" => Ok(Value::F64(self.0.y as f64)),
            "z" => Ok(Value::F64(self.0.z as f64)),
            "w" => Ok(Value::F64(self.0.w as f64)),
            _ => Err(format!("Quaternion has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {
        let f = extract_f32(&value, name)?;
        match name {
            "x" => self.0.x = f,
            "y" => self.0.y = f,
            "z" => self.0.z = f,
            "w" => self.0.w = f,
            _ => return Err(format!("Quaternion has no field '{name}'")),
        }
        Ok(())
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            "normalized" => Ok(quat_value(self.0.normalize())),
            "inverse" => Ok(quat_value(self.0.inverse())),
            "dot" => {
                let other = extract_quat(args, 0)?;
                Ok(Value::F64(self.0.dot(other) as f64))
            }
            "slerp" => {
                let other = extract_quat(args, 0)?;
                let t = extract_f32(args.get(1).ok_or("missing argument 't'")?, "t")?;
                Ok(quat_value(self.0.slerp(other, t)))
            }
            "lerp" => {
                let other = extract_quat(args, 0)?;
                let t = extract_f32(args.get(1).ok_or("missing argument 't'")?, "t")?;
                Ok(quat_value(self.0.lerp(other, t)))
            }
            "toEuler" => {
                let (x, y, z) = self.0.to_euler(glam::EulerRot::XYZ);
                Ok(vec3_value(glam::Vec3::new(x, y, z)))
            }
            "toMatrix" => Ok(mat4_value(glam::Mat4::from_quat(self.0))),
            "rotate" => {
                let v = extract_vec3(args, 0)?;
                Ok(vec3_value(self.0 * v))
            }
            "mul" => {
                let other = extract_quat(args, 0)?;
                Ok(quat_value(self.0 * other))
            }
            _ => Err(format!("Quaternion has no method '{name}'")),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

pub fn quat_value(q: Quat) -> Value {
    Value::Object(Rc::new(RefCell::new(WritQuaternion(q))))
}

pub fn extract_quat(args: &[Value], idx: usize) -> Result<Quat, String> {
    let v = args.get(idx).ok_or("missing Quaternion argument")?;
    match v {
        Value::Object(obj) => {
            let b = obj.borrow();
            b.as_any()
                .downcast_ref::<WritQuaternion>()
                .map(|q| q.0)
                .ok_or_else(|| format!("expected Quaternion, got {}", b.type_name()))
        }
        other => Err(format!("expected Quaternion, got {}", other.type_name())),
    }
}

pub fn register(vm: &mut VM) {
    vm.register_global("Quaternion_IDENTITY", quat_value(Quat::IDENTITY));

    vm.register_fn_in_module(
        "Quaternion_fromAxisAngle",
        "quaternion",
        crate::vm::binding::fn2(|axis: Value, angle: f64| -> Result<Value, String> {
            let ax = value_to_vec3(&axis)?;
            Ok(quat_value(Quat::from_axis_angle(ax, angle as f32)))
        }),
    );

    vm.register_fn_in_module(
        "Quaternion_fromEuler",
        "quaternion",
        crate::vm::binding::fn3(|x: f64, y: f64, z: f64| -> Result<Value, String> {
            Ok(quat_value(Quat::from_euler(
                glam::EulerRot::XYZ,
                x as f32,
                y as f32,
                z as f32,
            )))
        }),
    );

    vm.register_fn_in_module(
        "Quaternion_lookRotation",
        "quaternion",
        crate::vm::binding::fn2(|forward: Value, up: Value| -> Result<Value, String> {
            let f = value_to_vec3(&forward)?;
            let u = value_to_vec3(&up)?;
            let mat = glam::Mat4::look_to_rh(glam::Vec3::ZERO, f, u);
            Ok(quat_value(Quat::from_mat4(&mat)))
        }),
    );
}

use std::cell::RefCell;
use std::rc::Rc;

use crate::vm::binding::{fn0, fn1, fn2};
use crate::vm::{VM, Value};
use rand::Rng;

pub fn register(vm: &mut VM) {
    vm.register_fn_in_module(
        "random",
        "random",
        fn0(|| -> Result<f64, String> { Ok(rand::thread_rng().r#gen()) }),
    );

    vm.register_fn_in_module(
        "randomInt",
        "random",
        fn2(|min: i64, max: i64| -> Result<Value, String> {
            let val = rand::thread_rng().gen_range(min..=max);
            if let Ok(v) = i32::try_from(val) {
                Ok(Value::I32(v))
            } else {
                Ok(Value::I64(val))
            }
        }),
    );

    vm.register_fn_in_module(
        "randomFloat",
        "random",
        fn2(|min: f64, max: f64| -> Result<f64, String> {
            Ok(rand::thread_rng().gen_range(min..max))
        }),
    );

    vm.register_fn_in_module(
        "shuffle",
        "random",
        fn1(|arr: Rc<RefCell<Vec<Value>>>| -> Result<(), String> {
            let mut items = arr.borrow_mut();
            let len = items.len();
            if len > 1 {
                let mut rng = rand::thread_rng();
                for i in (1..len).rev() {
                    let j = rng.gen_range(0..=i);
                    items.swap(i, j);
                }
            }
            Ok(())
        }),
    );
}

use std::cell::RefCell;
use std::rc::Rc;

use crate::vm::{VM, Value, WritObject};
use glam::{Vec2, Vec3};

use super::vector::{extract_f32, extract_vec2, extract_vec3, vec2_value, vec3_value};

// --- Rectangle ---

#[derive(Debug, Clone)]
pub struct WritRectangle {
    pub position: Vec2,
    pub size: Vec2,
}

impl WritObject for WritRectangle {
    fn type_name(&self) -> &str {
        "Rectangle"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "position" => Ok(vec2_value(self.position)),
            "size" => Ok(vec2_value(self.size)),
            _ => Err(format!("Rectangle has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {
        match name {
            "position" => {
                self.position = super::vector::value_to_vec2(&value)?;
                Ok(())
            }
            "size" => {
                self.size = super::vector::value_to_vec2(&value)?;
                Ok(())
            }
            _ => Err(format!("Rectangle has no field '{name}'")),
        }
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            "width" => Ok(Value::F64(self.size.x as f64)),
            "height" => Ok(Value::F64(self.size.y as f64)),
            "center" => Ok(vec2_value(self.position + self.size * 0.5)),
            "area" => Ok(Value::F64((self.size.x * self.size.y) as f64)),
            "contains" => {
                let p = extract_vec2(args, 0)?;
                let inside = p.x >= self.position.x
                    && p.y >= self.position.y
                    && p.x <= self.position.x + self.size.x
                    && p.y <= self.position.y + self.size.y;
                Ok(Value::Bool(inside))
            }
            "intersects" => {
                let other = extract_rect(args, 0)?;
                let intersects = self.position.x < other.position.x + other.size.x
                    && self.position.x + self.size.x > other.position.x
                    && self.position.y < other.position.y + other.size.y
                    && self.position.y + self.size.y > other.position.y;
                Ok(Value::Bool(intersects))
            }
            "intersection" => {
                let other = extract_rect(args, 0)?;
                let x1 = self.position.x.max(other.position.x);
                let y1 = self.position.y.max(other.position.y);
                let x2 = (self.position.x + self.size.x).min(other.position.x + other.size.x);
                let y2 = (self.position.y + self.size.y).min(other.position.y + other.size.y);
                if x2 > x1 && y2 > y1 {
                    Ok(rect_value(WritRectangle {
                        position: Vec2::new(x1, y1),
                        size: Vec2::new(x2 - x1, y2 - y1),
                    }))
                } else {
                    Ok(Value::Null)
                }
            }
            "merge" => {
                let other = extract_rect(args, 0)?;
                let min = self.position.min(other.position);
                let max = (self.position + self.size).max(other.position + other.size);
                Ok(rect_value(WritRectangle {
                    position: min,
                    size: max - min,
                }))
            }
            "expand" => {
                let amount = extract_f32(args.first().ok_or("missing amount argument")?, "amount")?;
                Ok(rect_value(WritRectangle {
                    position: self.position - Vec2::splat(amount),
                    size: self.size + Vec2::splat(amount * 2.0),
                }))
            }
            _ => Err(format!("Rectangle has no method '{name}'")),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

// --- BoundingBox ---

#[derive(Debug, Clone)]
pub struct WritBoundingBox {
    pub min: Vec3,
    pub max: Vec3,
}

impl WritObject for WritBoundingBox {
    fn type_name(&self) -> &str {
        "BoundingBox"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "min" => Ok(vec3_value(self.min)),
            "max" => Ok(vec3_value(self.max)),
            _ => Err(format!("BoundingBox has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {
        match name {
            "min" => {
                self.min = super::vector::value_to_vec3(&value)?;
                Ok(())
            }
            "max" => {
                self.max = super::vector::value_to_vec3(&value)?;
                Ok(())
            }
            _ => Err(format!("BoundingBox has no field '{name}'")),
        }
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            "size" => Ok(vec3_value(self.max - self.min)),
            "center" => Ok(vec3_value((self.min + self.max) * 0.5)),
            "volume" => {
                let s = self.max - self.min;
                Ok(Value::F64((s.x * s.y * s.z) as f64))
            }
            "contains" => {
                let p = extract_vec3(args, 0)?;
                let inside = p.x >= self.min.x
                    && p.y >= self.min.y
                    && p.z >= self.min.z
                    && p.x <= self.max.x
                    && p.y <= self.max.y
                    && p.z <= self.max.z;
                Ok(Value::Bool(inside))
            }
            "intersects" => {
                let other = extract_bbox(args, 0)?;
                let intersects = self.min.x <= other.max.x
                    && self.max.x >= other.min.x
                    && self.min.y <= other.max.y
                    && self.max.y >= other.min.y
                    && self.min.z <= other.max.z
                    && self.max.z >= other.min.z;
                Ok(Value::Bool(intersects))
            }
            "intersection" => {
                let other = extract_bbox(args, 0)?;
                let new_min = self.min.max(other.min);
                let new_max = self.max.min(other.max);
                if new_min.x < new_max.x && new_min.y < new_max.y && new_min.z < new_max.z {
                    Ok(bbox_value(WritBoundingBox {
                        min: new_min,
                        max: new_max,
                    }))
                } else {
                    Ok(Value::Null)
                }
            }
            "merge" => {
                let other = extract_bbox(args, 0)?;
                Ok(bbox_value(WritBoundingBox {
                    min: self.min.min(other.min),
                    max: self.max.max(other.max),
                }))
            }
            "expand" => {
                let amount = extract_f32(args.first().ok_or("missing amount argument")?, "amount")?;
                Ok(bbox_value(WritBoundingBox {
                    min: self.min - Vec3::splat(amount),
                    max: self.max + Vec3::splat(amount),
                }))
            }
            _ => Err(format!("BoundingBox has no method '{name}'")),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

// --- Value constructors ---

fn rect_value(r: WritRectangle) -> Value {
    Value::Object(Rc::new(RefCell::new(r)))
}

fn bbox_value(b: WritBoundingBox) -> Value {
    Value::Object(Rc::new(RefCell::new(b)))
}

// --- Extraction helpers ---

fn extract_rect(args: &[Value], idx: usize) -> Result<WritRectangle, String> {
    let v = args.get(idx).ok_or("missing Rectangle argument")?;
    match v {
        Value::Object(obj) => {
            let b = obj.borrow();
            b.as_any()
                .downcast_ref::<WritRectangle>()
                .cloned()
                .ok_or_else(|| format!("expected Rectangle, got {}", b.type_name()))
        }
        other => Err(format!("expected Rectangle, got {}", other.type_name())),
    }
}

fn extract_bbox(args: &[Value], idx: usize) -> Result<WritBoundingBox, String> {
    let v = args.get(idx).ok_or("missing BoundingBox argument")?;
    match v {
        Value::Object(obj) => {
            let b = obj.borrow();
            b.as_any()
                .downcast_ref::<WritBoundingBox>()
                .cloned()
                .ok_or_else(|| format!("expected BoundingBox, got {}", b.type_name()))
        }
        other => Err(format!("expected BoundingBox, got {}", other.type_name())),
    }
}

// --- Registration ---

pub fn register(vm: &mut VM) {
    vm.register_type("Rectangle", |args| {
        let x = extract_f32(args.first().ok_or("Rectangle: missing x")?, "x")?;
        let y = extract_f32(args.get(1).ok_or("Rectangle: missing y")?, "y")?;
        let w = extract_f32(args.get(2).ok_or("Rectangle: missing width")?, "width")?;
        let h = extract_f32(args.get(3).ok_or("Rectangle: missing height")?, "height")?;
        Ok(Box::new(WritRectangle {
            position: Vec2::new(x, y),
            size: Vec2::new(w, h),
        }))
    });

    vm.register_fn_in_module(
        "Rectangle_fromPoints",
        "rect",
        crate::vm::binding::fn2(|min: Value, max: Value| -> Result<Value, String> {
            let mn = super::vector::value_to_vec2(&min)?;
            let mx = super::vector::value_to_vec2(&max)?;
            Ok(rect_value(WritRectangle {
                position: mn,
                size: mx - mn,
            }))
        }),
    );

    vm.register_type("BoundingBox", |args| {
        let min = super::vector::value_to_vec3(args.first().ok_or("BoundingBox: missing min")?)?;
        let max = super::vector::value_to_vec3(args.get(1).ok_or("BoundingBox: missing max")?)?;
        Ok(Box::new(WritBoundingBox { min, max }))
    });
}

use std::cell::RefCell;
use std::rc::Rc;

#[cfg(test)]
use crate::vm::WritStruct;
use crate::vm::binding::{fn1, fn2, fn3};
use crate::vm::{VM, Value};

pub fn register(vm: &mut VM) {
    vm.register_fn(
        "typeof",
        fn1(|v: Value| -> Result<Value, String> {
            Ok(Value::Str(Rc::from(v.type_name_owned().as_str())))
        }),
    );

    vm.register_fn(
        "instanceof",
        fn2(|v: Value, type_name: String| -> Result<bool, String> {
            Ok(v.type_name_owned() == type_name)
        }),
    );

    vm.register_fn(
        "hasField",
        fn2(|obj: Value, name: String| -> Result<bool, String> {
            let result = match &obj {
                Value::Struct(s) => s.layout.public_fields.contains(&name),
                Value::Dict(d) => d.borrow().contains_key(&name),
                Value::Object(o) => o.borrow().get_field(&name).is_ok(),
                _ => false,
            };
            Ok(result)
        }),
    );

    vm.register_fn(
        "getField",
        fn2(|obj: Value, name: String| -> Result<Value, String> {
            match obj {
                Value::Struct(s) => {
                    if !s.layout.public_fields.contains(&name) {
                        return Err(format!(
                            "field '{}' not found on '{}'",
                            name, s.layout.type_name
                        ));
                    }
                    s.get_field(&name).cloned().ok_or_else(|| {
                        format!("field '{}' not found on '{}'", name, s.layout.type_name)
                    })
                }
                Value::Dict(d) => Ok(d.borrow().get(&name).cloned().unwrap_or(Value::Null)),
                Value::Object(o) => o.borrow().get_field(&name),
                other => Err(format!("cannot get field on {}", other.type_name())),
            }
        }),
    );

    vm.register_fn(
        "setField",
       fn3(|obj: Value, name: String, value: Value| -> Result<(), String> {
            match &obj {
                Value::Dict(d) => {
                    d.borrow_mut().insert(name, value);
                    Ok(())
                }
                Value::Object(o) => o.borrow_mut().set_field(&name, value),
                Value::Struct(_) => Err(
                    "setField cannot modify structs (value types); use direct field assignment instead"
                        .to_string(),
                ),
                other => Err(format!("cannot set field on {}", other.type_name())),
            }
        }),
    );

    vm.register_fn(
        "fields",
        fn1(|obj: Value| -> Result<Value, String> {
            let names: Vec<Value> = match &obj {
                Value::Struct(s) => s
                    .public_field_names()
                    .into_iter()
                    .map(|n| Value::Str(Rc::from(n.as_str())))
                    .collect(),
                Value::Dict(d) => d
                    .borrow()
                    .keys()
                    .map(|k| Value::Str(Rc::from(k.as_str())))
                    .collect(),
                _ => Vec::new(),
            };
            Ok(Value::Array(Rc::new(RefCell::new(names))))
        }),
    );

    vm.register_fn(
        "methods",
        fn1(|obj: Value| -> Result<Value, String> {
            let names: Vec<Value> = match &obj {
                Value::Struct(s) => s
                    .public_method_names()
                    .into_iter()
                    .map(|n| Value::Str(Rc::from(n.as_str())))
                    .collect(),
                _ => Vec::new(),
            };
            Ok(Value::Array(Rc::new(RefCell::new(names))))
        }),
    );

    vm.register_fn(
        "hasMethod",
        fn2(|obj: Value, name: String| -> Result<bool, String> {
            let result = match &obj {
                Value::Struct(s) => s.layout.public_methods.contains(&name),
                _ => false,
            };
            Ok(result)
        }),
    );
}

use std::cell::RefCell;
use std::rc::Rc;

use crate::vm::{VM, Value, WritObject};
use regex::Regex;

#[derive(Debug)]
struct WritRegex {
    pattern: Regex,
    source: String,
}

impl WritRegex {
    fn new(pattern: &str) -> Result<Self, String> {
        Regex::new(pattern)
            .map(|r| Self {
                pattern: r,
                source: pattern.to_string(),
            })
            .map_err(|e| format!("invalid regex: {e}"))
    }
}

impl WritObject for WritRegex {
    fn type_name(&self) -> &str {
        "Regex"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "source" => Ok(Value::Str(Rc::from(self.source.as_str()))),
            _ => Err(format!("Regex has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, _value: Value) -> Result<(), String> {
        Err(format!("Regex has no settable field '{name}'"))
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            // .match(input: string) -> Optional<string>
            // Returns the first full match, or null if no match.
            "match" => {
                let input = extract_str(args.first(), "match")?;
                match self.pattern.find(&input) {
                    Some(m) => Ok(Value::Str(Rc::from(m.as_str()))),
                    None => Ok(Value::Null),
                }
            }

            // .matchAll(input: string) -> Array<string>
            // Returns all non-overlapping matches as an array of strings.
            "matchAll" => {
                let input = extract_str(args.first(), "matchAll")?;
                let matches: Vec<Value> = self
                    .pattern
                    .find_iter(&input)
                    .map(|m| Value::Str(Rc::from(m.as_str())))
                    .collect();
                Ok(Value::Array(Rc::new(RefCell::new(matches))))
            }

            // .replace(input: string, replacement: string) -> string
            // Replaces the first occurrence. Use $1, $2 etc. for capture groups.
            "replace" => {
                let input = extract_str(args.first(), "replace: input")?;
                let replacement = extract_str(args.get(1), "replace: replacement")?;
                Ok(Value::Str(Rc::from(
                    self.pattern
                        .replacen(&input, 1, replacement.as_str())
                        .as_ref(),
                )))
            }

            // .replaceAll(input: string, replacement: string) -> string
            // Replaces all occurrences.
            "replaceAll" => {
                let input = extract_str(args.first(), "replaceAll: input")?;
                let replacement = extract_str(args.get(1), "replaceAll: replacement")?;
                Ok(Value::Str(Rc::from(
                    self.pattern
                        .replace_all(&input, replacement.as_str())
                        .as_ref(),
                )))
            }

            // .test(input: string) -> bool
            // Returns true if the pattern matches anywhere in the input.
            "test" => {
                let input = extract_str(args.first(), "test")?;
                Ok(Value::Bool(self.pattern.is_match(&input)))
            }

            _ => Err(format!("Regex has no method '{name}'")),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

fn extract_str(val: Option<&Value>, context: &str) -> Result<String, String> {
    match val {
        Some(Value::Str(s)) => Ok(s.to_string()),
        Some(other) => Err(format!(
            "{context}: expected string, got {}",
            other.type_name()
        )),
        None => Err(format!("{context}: missing string argument")),
    }
}

pub fn register(vm: &mut VM) {
    vm.register_type("Regex", |args| {
        let pattern = match args.first() {
            Some(Value::Str(s)) => s.to_string(),
            Some(other) => {
                return Err(format!(
                    "Regex: expected string pattern, got {}",
                    other.type_name()
                ));
            }
            None => return Err("Regex: missing pattern argument".to_string()),
        };
        Ok(Box::new(WritRegex::new(&pattern)?))
    });
}

use std::cell::RefCell;
use std::rc::Rc;

use crate::vm::binding::{mfn0, mfn1, mfn2};
use crate::vm::{VM, Value, ValueTag};

type RcStr = Rc<str>;
type Arr = Rc<RefCell<Vec<Value>>>;

pub fn register(vm: &mut VM) {
    vm.register_method(
        ValueTag::Str,
        "len",
        Some("string"),
        mfn0(|s: RcStr| -> Result<i32, String> { Ok(s.len() as i32) }),
    );

    vm.register_method(
        ValueTag::Str,
        "trim",
        Some("string"),
        mfn0(|s: RcStr| -> Result<String, String> { Ok(s.trim().to_string()) }),
    );

    vm.register_method(
        ValueTag::Str,
        "trimStart",
        Some("string"),
        mfn0(|s: RcStr| -> Result<String, String> { Ok(s.trim_start().to_string()) }),
    );

    vm.register_method(
        ValueTag::Str,
        "trimEnd",
        Some("string"),
        mfn0(|s: RcStr| -> Result<String, String> { Ok(s.trim_end().to_string()) }),
    );

    vm.register_method(
        ValueTag::Str,
        "toUpper",
        Some("string"),
        mfn0(|s: RcStr| -> Result<String, String> { Ok(s.to_uppercase()) }),
    );

    vm.register_method(
        ValueTag::Str,
        "toLower",
        Some("string"),
        mfn0(|s: RcStr| -> Result<String, String> { Ok(s.to_lowercase()) }),
    );

    vm.register_method(
        ValueTag::Str,
        "contains",
        Some("string"),
        mfn1(|s: RcStr, needle: RcStr| -> Result<bool, String> { Ok(s.contains(&*needle)) }),
    );

    vm.register_method(
        ValueTag::Str,
        "startsWith",
        Some("string"),
        mfn1(|s: RcStr, prefix: RcStr| -> Result<bool, String> { Ok(s.starts_with(&*prefix)) }),
    );

    vm.register_method(
        ValueTag::Str,
        "endsWith",
        Some("string"),
        mfn1(|s: RcStr, suffix: RcStr| -> Result<bool, String> { Ok(s.ends_with(&*suffix)) }),
    );

    vm.register_method(
        ValueTag::Str,
        "replace",
        Some("string"),
        mfn2(
            |s: RcStr, old: RcStr, new: RcStr| -> Result<String, String> {
                Ok(s.replace(&*old, &new))
            },
        ),
    );

    vm.register_method(
        ValueTag::Str,
        "split",
        Some("string"),
        mfn1(|s: RcStr, separator: RcStr| -> Result<Value, String> {
            let parts: Vec<Value> = s
                .split(&*separator)
                .map(|part| Value::Str(Rc::from(part)))
                .collect();
            Ok(Value::Array(Rc::new(RefCell::new(parts))))
        }),
    );

    vm.register_method(
        ValueTag::Str,
        "join",
        Some("string"),
        mfn1(|separator: RcStr, arr: Arr| -> Result<String, String> {
            let items = arr.borrow();
            let parts: Vec<String> = items
                .iter()
                .map(|v| match v {
                    Value::Str(s) => s.to_string(),
                    other => other.to_string(),
                })
                .collect();
            Ok(parts.join(&*separator))
        }),
    );

    vm.register_method(
        ValueTag::Str,
        "charAt",
        Some("string"),
        mfn1(|s: RcStr, idx: i64| -> Result<Value, String> {
            match s.chars().nth(idx as usize) {
                Some(c) => Ok(Value::Str(Rc::from(c.to_string().as_str()))),
                None => Ok(Value::Null),
            }
        }),
    );

    vm.register_method(
        ValueTag::Str,
        "indexOf",
        Some("string"),
        mfn1(|s: RcStr, needle: RcStr| -> Result<i32, String> {
            Ok(match s.find(&*needle) {
                Some(pos) => pos as i32,
                None => -1,
            })
        }),
    );

    vm.register_method(
        ValueTag::Str,
        "parse",
        Some("string"),
        mfn0(|s: RcStr| -> Result<Value, String> {
            let trimmed = s.trim();
            if let Ok(i) = trimmed.parse::<i64>() {
                if let Ok(v) = i32::try_from(i) {
                    return Ok(Value::I32(v));
                }
                return Ok(Value::I64(i));
            }
            if let Ok(f) = trimmed.parse::<f64>() {
                return Ok(Value::F64(f));
            }
            Err(format!("cannot parse '{}' as a number", s))
        }),
    );
}

use std::time::{SystemTime, UNIX_EPOCH};

use crate::vm::VM;
