        fn0(|| -> Result<f64, String> {
            Ok(SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap()
                .as_secs_f64())
        }),
    );

    vm.register_fn_in_module(
        "elapsed",
        "time",
