    extract_f32, extract_vec2, extract_vec3, value_to_vec2, value_to_vec3, vec2_value, vec3_value,
};

// --- Transform2D ---

#[derive(Debug, Clone)]
pub struct WritTransform2D {
    pub position: Vec2,
    pub rotation: f32,
    pub scale: Vec2,
}

impl WritObject for WritTransform2D {
    fn type_name(&self) -> &str {
        "Transform2D"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "position" => Ok(vec2_value(self.position)),
            "rotation" => Ok(Value::F64(self.rotation as f64)),
            "scale" => Ok(vec2_value(self.scale)),
            _ => Err(format!("Transform2D has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {
        match name {
            "position" => {
                self.position = value_to_vec2(&value)?;
                Ok(())
            }
            "rotation" => {
                self.rotation = extract_f32(&value, "rotation")?;
                Ok(())
            }
            "scale" => {
                self.scale = value_to_vec2(&value)?;
                Ok(())
            }
            _ => Err(format!("Transform2D has no field '{name}'")),
        }
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            "toMatrix" => {
                let m =
                    Mat3::from_scale_angle_translation(self.scale, self.rotation, self.position);
                Ok(mat3_value(m))
            }
            "inverse" => Ok(transform2d_value(WritTransform2D {
                position: -self.position,
                rotation: -self.rotation,
                scale: Vec2::new(1.0 / self.scale.x, 1.0 / self.scale.y),
            })),
            "transformPoint" => {
                let v = extract_vec2(args, 0)?;
                let rotated = Vec2::new(
                    v.x * self.rotation.cos() - v.y * self.rotation.sin(),
                    v.x * self.rotation.sin() + v.y * self.rotation.cos(),
                );
                Ok(vec2_value(rotated * self.scale + self.position))
            }
            "transformVector" => {
                let v = extract_vec2(args, 0)?;
                let rotated = Vec2::new(
                    v.x * self.rotation.cos() - v.y * self.rotation.sin(),
                    v.x * self.rotation.sin() + v.y * self.rotation.cos(),
                );
                Ok(vec2_value(rotated * self.scale))
            }
            "translate" => {
                let offset = extract_vec2(args, 0)?;
                self.position += offset;
                Ok(Value::Null)
            }
            "rotate" => {
                let angle = extract_f32(args.first().ok_or("missing angle argument")?, "angle")?;
                self.rotation += angle;
                Ok(Value::Null)
            }
            "lookAt" => {
                let target = extract_vec2(args, 0)?;
                let diff = target - self.position;
                self.rotation = diff.y.atan2(diff.x);
                Ok(Value::Null)
            }
            _ => Err(format!("Transform2D has no method '{name}'")),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

// --- Transform3D ---

#[derive(Debug, Clone)]
pub struct WritTransform3D {
    pub position: Vec3,
    pub rotation: Quat,
    pub scale: Vec3,
}

impl WritObject for WritTransform3D {
    fn type_name(&self) -> &str {
        "Transform3D"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "position" => Ok(vec3_value(self.position)),
            "rotation" => Ok(quat_value(self.rotation)),
            "scale" => Ok(vec3_value(self.scale)),
            _ => Err(format!("Transform3D has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {
        match name {
            "position" => {
                self.position = value_to_vec3(&value)?;
                Ok(())
            }
            "rotation" => {
                self.rotation = extract_quat(&[value], 0)?;
                Ok(())
            }
            "scale" => {
                self.scale = value_to_vec3(&value)?;
                Ok(())
            }
            _ => Err(format!("Transform3D has no field '{name}'")),
        }
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            "toMatrix" => {
                let m =
                    Mat4::from_scale_rotation_translation(self.scale, self.rotation, self.position);
                Ok(mat4_value(m))
            }
            "inverse" => Ok(transform3d_value(WritTransform3D {
                position: -(self.rotation.inverse() * self.position),
                rotation: self.rotation.inverse(),
                scale: Vec3::new(1.0 / self.scale.x, 1.0 / self.scale.y, 1.0 / self.scale.z),
            })),
            "transformPoint" => {
                let v = extract_vec3(args, 0)?;
                Ok(vec3_value(self.rotation * (v * self.scale) + self.position))
            }
            "transformVector" => {
                let v = extract_vec3(args, 0)?;
                Ok(vec3_value(self.rotation * (v * self.scale)))
            }
            "translate" => {
                let offset = extract_vec3(args, 0)?;
                self.position += offset;
                Ok(Value::Null)
            }
            "rotate" => {
                let axis = extract_vec3(args, 0)?;
                let angle = extract_f32(args.get(1).ok_or("missing angle argument")?, "angle")?;
                self.rotation = Quat::from_axis_angle(axis, angle) * self.rotation;
                Ok(Value::Null)
            }
            "lookAt" => {
                let target = extract_vec3(args, 0)?;
                let up = extract_vec3(args, 1)?;
                let forward = (target - self.position).normalize();
                let right = up.cross(forward).normalize();
                let corrected_up = forward.cross(right);
                self.rotation =
                    Quat::from_mat3(&glam::Mat3::from_cols(right, corrected_up, forward));
                Ok(Value::Null)
            }
            _ => Err(format!("Transform3D has no method '{name}'")),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

// --- Value constructors ---

fn transform2d_value(t: WritTransform2D) -> Value {
    Value::Object(Rc::new(RefCell::new(t)))
}

fn transform3d_value(t: WritTransform3D) -> Value {
    Value::Object(Rc::new(RefCell::new(t)))
}

// --- Registration ---

pub fn register(vm: &mut VM) {
    vm.register_type("Transform2D", |args| {
        if args.is_empty() {
            return Ok(Box::new(WritTransform2D {
                position: Vec2::ZERO,
                rotation: 0.0,
                scale: Vec2::ONE,
            }));
        }
        let pos = value_to_vec2(args.first().ok_or("missing position")?)?;
        let rot = extract_f32(args.get(1).ok_or("missing rotation")?, "rotation")?;
        let scale = value_to_vec2(args.get(2).ok_or("missing scale")?)?;
        Ok(Box::new(WritTransform2D {
            position: pos,
            rotation: rot,
            scale,
        }))
    });

    vm.register_type("Transform3D", |args| {
        if args.is_empty() {
            return Ok(Box::new(WritTransform3D {
                position: Vec3::ZERO,
                rotation: Quat::IDENTITY,
                scale: Vec3::ONE,
            }));
        }
        let pos = value_to_vec3(args.first().ok_or("missing position")?)?;
        let rot = extract_quat(args, 1)?;
        let scale = value_to_vec3(args.get(2).ok_or("missing scale")?)?;
        Ok(Box::new(WritTransform3D {
            position: pos,
            rotation: rot,
            scale,
        }))
    });
}

use std::fmt;
use std::rc::Rc;

use crate::vm::{VM, Value, WritObject};

use super::vector::extract_f64;

#[derive(Clone, Copy, PartialEq)]
enum LoopMode {
    None,
    Loop,
    PingPong,
}

impl fmt::Debug for LoopMode {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            LoopMode::None => write!(f, "None"),
            LoopMode::Loop => write!(f, "Loop"),
            LoopMode::PingPong => write!(f, "PingPong"),
        }
    }
}

struct WritTween {
    from: f64,
    to: f64,
    duration: f64,
    elapsed: f64,
    delay: f64,
    loop_mode: LoopMode,
    easing: Option<Rc<dyn Fn(f64) -> f64>>,
    finished: bool,
    direction: f64,
}

impl fmt::Debug for WritTween {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("Tween")
            .field("from", &self.from)
            .field("to", &self.to)
            .field("duration", &self.duration)
            .field("elapsed", &self.elapsed)
            .field("finished", &self.finished)
            .finish()
    }
}

impl WritTween {
    fn new(from: f64, to: f64, duration: f64) -> Self {
        Self {
            from,
            to,
            duration,
            elapsed: 0.0,
            delay: 0.0,
            loop_mode: LoopMode::None,
            easing: None,
            finished: false,
            direction: 1.0,
        }
    }

    fn raw_t(&self) -> f64 {
        if self.duration <= 0.0 {
            return 1.0;
        }
        ((self.elapsed - self.delay).max(0.0) / self.duration).clamp(0.0, 1.0)
    }

    fn current_value(&self) -> f64 {
        let t = self.raw_t();
        let eased = match &self.easing {
            Some(f) => f(t),
            None => t,
        };
        self.from + (self.to - self.from) * eased
    }
}

impl WritObject for WritTween {
    fn type_name(&self) -> &str {
        "Tween"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        Err(format!("Tween has no field '{}'", name))
    }

    fn set_field(&mut self, name: &str, _value: Value) -> Result<(), String> {
        Err(format!("Tween has no field '{}'", name))
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            "setEasing" => match args.first() {
                Some(Value::Str(s)) => {
                    let f: Rc<dyn Fn(f64) -> f64> = match &**s {
                        "linear" => Rc::new(|t| t),
                        "easeInQuad" => Rc::new(|t| t * t),
                        "easeOutQuad" => Rc::new(|t| 1.0 - (1.0 - t) * (1.0 - t)),
                        "easeInOutQuad" => Rc::new(|t| {
                            if t < 0.5 {
                                2.0 * t * t
                            } else {
                                1.0 - (-2.0 * t + 2.0).powi(2) / 2.0
                            }
                        }),
                        "easeInCubic" => Rc::new(|t| t * t * t),
                        "easeOutCubic" => Rc::new(|t| 1.0 - (1.0 - t).powi(3)),
                        "easeInOutCubic" => Rc::new(|t| {
                            if t < 0.5 {
                                4.0 * t * t * t
                            } else {
                                1.0 - (-2.0 * t + 2.0).powi(3) / 2.0
                            }
                        }),
                        "smoothstep" => Rc::new(|t| t * t * (3.0 - 2.0 * t)),
                        _ => return Err(format!("unknown easing: {}", s)),
                    };
                    self.easing = Some(f);
                    Ok(Value::Null)
                }
                _ => Err("setEasing expects a string easing name".into()),
            },
            "setLoop" => {
                let mode = match args.first() {
                    Some(Value::Str(s)) => match &**s {
                        "none" => LoopMode::None,
                        "loop" => LoopMode::Loop,
                        "pingpong" => LoopMode::PingPong,
                        _ => return Err(format!("unknown loop mode: {}", s)),
                    },
                    _ => return Err("setLoop expects a string".into()),
                };
                self.loop_mode = mode;
                Ok(Value::Null)
            }
            "setDelay" => {
                let d = extract_f64(args.first().ok_or("missing delay")?, "delay")?;
                self.delay = d;
                Ok(Value::Null)
            }
            "update" => {
                let delta = extract_f64(args.first().ok_or("missing delta")?, "delta")?;
                if self.finished {
                    return Ok(Value::F64(self.current_value()));
                }
                self.elapsed += delta * self.direction;

                let active_elapsed = self.elapsed - self.delay;
                if active_elapsed >= self.duration {
                    match self.loop_mode {
                        LoopMode::None => {
                            self.elapsed = self.delay + self.duration;
                            self.finished = true;
                        }
                        LoopMode::Loop => {
                            self.elapsed -= self.duration;
                        }
                        LoopMode::PingPong => {
                            self.direction = -self.direction;
                            self.elapsed = self.delay + self.duration;
                        }
                    }
                } else if active_elapsed < 0.0 && self.loop_mode == LoopMode::PingPong {
                    self.direction = -self.direction;
                    self.elapsed = self.delay;
                }

                Ok(Value::F64(self.current_value()))
            }
            "value" => Ok(Value::F64(self.current_value())),
            "isFinished" => Ok(Value::Bool(self.finished)),
            "reset" => {
                self.elapsed = 0.0;
                self.finished = false;
                self.direction = 1.0;
                Ok(Value::Null)
            }
            _ => Err(format!("Tween has no method '{}'", name)),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

pub fn register(vm: &mut VM) {
    vm.register_type("Tween", |args| {
        let from = extract_f64(args.first().ok_or("Tween: missing from")?, "from")?;
        let to = extract_f64(args.get(1).ok_or("Tween: missing to")?, "to")?;
        let duration = extract_f64(args.get(2).ok_or("Tween: missing duration")?, "duration")?;
        Ok(Box::new(WritTween::new(from, to, duration)))
    });
}

use std::cell::RefCell;
use std::rc::Rc;

use crate::vm::WritObject;
use crate::vm::{VM, Value};
use glam::{Vec2, Vec3, Vec4};

// --- Vector2 ---

#[derive(Debug, Clone)]
pub struct WritVector2(pub Vec2);

impl WritObject for WritVector2 {
    fn type_name(&self) -> &str {
        "Vector2"
    }

    fn get_field(&self, name: &str) -> Result<Value, String> {
        match name {
            "x" => Ok(Value::F64(self.0.x as f64)),
            "y" => Ok(Value::F64(self.0.y as f64)),
            _ => Err(format!("Vector2 has no field '{name}'")),
        }
    }

    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {
        let f = extract_f32(&value, name)?;
        match name {
            "x" => self.0.x = f,
            "y" => self.0.y = f,
            _ => return Err(format!("Vector2 has no field '{name}'")),
        }
        Ok(())
    }

    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        match name {
            "length" => Ok(Value::F64(self.0.length() as f64)),
            "lengthSquared" => Ok(Value::F64(self.0.length_squared() as f64)),
            "normalized" => Ok(vec2_value(self.0.normalize_or_zero())),
            "dot" => {
                let other = extract_vec2(args, 0)?;
                Ok(Value::F64(self.0.dot(other) as f64))
            }
            "distance" => {
                let other = extract_vec2(args, 0)?;
                Ok(Value::F64(self.0.distance(other) as f64))
            }
            "distanceSquared" => {
                let other = extract_vec2(args, 0)?;
                Ok(Value::F64(self.0.distance_squared(other) as f64))
            }
            "lerp" => {
                let other = extract_vec2(args, 0)?;
                let t = extract_f32_arg(args, 1, "t")?;
                Ok(vec2_value(self.0.lerp(other, t)))
            }
            "clamp" => {
                let min = extract_vec2(args, 0)?;
                let max = extract_vec2(args, 1)?;
                Ok(vec2_value(self.0.clamp(min, max)))
            }
            "abs" => Ok(vec2_value(self.0.abs())),
            "sign" => Ok(vec2_value(self.0.signum())),
