use std::collections::{HashMap, HashSet};

use crate::compiler::string_hash;

/// Shared field layout for all instances of a given struct or class type.
///
/// Built once at load time from `StructMeta`/`ClassMeta`. Shared via `Rc`
/// across all instances of the same type to avoid per-instance string
/// cloning and per-access HashMap lookups.
#[derive(Debug, Clone)]
pub struct FieldLayout {
    /// The type name (e.g. "Point", "Player").
    pub type_name: String,
    /// Number of fields (length of the instance's `Vec<Value>`).
    pub field_count: usize,
    /// Maps field name hash (FNV-1a u32) to index in the `Vec<Value>`.
    pub hash_to_index: HashMap<u32, usize>,
    /// Field names in declaration order (index i = field_names\[i\]).
    /// Used for Display, Hash, reflection, and AoSoA interop.
    pub field_names: Vec<String>,
    /// Set of public field names (for hasField/fields reflection).
    pub public_fields: HashSet<String>,
    /// Set of public method names (for hasMethod/methods reflection).
    pub public_methods: HashSet<String>,
}

impl FieldLayout {
    /// Builds a `FieldLayout` from field names and visibility sets.
    pub fn new(
        type_name: String,
        field_names: Vec<String>,
        public_fields: HashSet<String>,
        public_methods: HashSet<String>,
    ) -> Self {
        let field_count = field_names.len();
        let mut hash_to_index = HashMap::with_capacity(field_count);
        for (i, name) in field_names.iter().enumerate() {
            let prev = hash_to_index.insert(string_hash(name), i);
            debug_assert!(
                prev.is_none(),
                "FNV-1a hash collision for fields in type '{type_name}': '{}' collides at index {i}",
                name
            );
        }
        Self {
            type_name,
            field_count,
            hash_to_index,
            field_names,
            public_fields,
            public_methods,
        }
    }
}

/// Identifies which chunk a CallFrame is executing.
#[derive(Debug, Clone, Copy)]
pub(crate) enum ChunkId {
    /// The main/top-level script chunk.
    Main,
    /// A function chunk, by index in the function table.
    Function(usize),
}

/// A single activation record on the call stack.
///
/// In the register-based VM, each frame owns a window of the value stack
/// `[base .. base + max_registers)`. Parameters occupy the first `arity`
/// registers, locals follow, then temporaries.
///
/// Upvalue indices are stored in a parallel side table (`frame_upvalues`)
/// on the VM, not inline here. This keeps CallFrame small and
/// trivially-droppable for non-closure frames.
#[derive(Debug, Clone, Copy)]
pub(crate) struct CallFrame {
    /// Which chunk this frame is executing.
    pub chunk_id: ChunkId,
    /// Program counter -- index of the next instruction to execute.
    pub pc: usize,
    /// Base stack pointer -- index into the operand stack where this
    /// frame's register window begins.
    pub base: usize,
    /// Absolute stack position where the return value should be written.
    /// For the top-level frame, this is unused (set to 0).
    pub result_reg: usize,
    /// Maximum number of registers this frame uses.
    pub max_registers: u8,
    /// True if any register may hold an Rc-bearing value. When false, the
    /// return handler can use `set_len` instead of `truncate` (skips drops).
    pub has_rc_values: bool,
}

impl CallFrame {
    /// Returns the function index if this frame executes a function chunk.
    #[inline(always)]
    pub fn func_index(&self) -> Option<usize> {
        match self.chunk_id {
            ChunkId::Main => None,
            ChunkId::Function(idx) => Some(idx),
        }
    }
}

use std::collections::HashMap;
use std::rc::Rc;

/// A string interner that deduplicates `Rc<str>` allocations across chunks.
///
/// Identical string literals in different function chunks share a single
/// `Rc<str>`, enabling O(1) pointer-based equality via `Rc::ptr_eq`.
pub struct StringInterner {
    map: HashMap<String, Rc<str>>,
}

impl Default for StringInterner {
    fn default() -> Self {
        Self::new()
    }
}

impl StringInterner {
    pub fn new() -> Self {
        Self {
            map: HashMap::with_capacity(256),
        }
    }

    /// Interns a string slice, returning the canonical `Rc<str>`.
    ///
    /// If the string was previously interned, returns a clone of the
    /// existing `Rc` (refcount bump only). Otherwise allocates a new
    /// `Rc<str>` and stores it.
    #[inline]
    pub fn intern(&mut self, s: &str) -> Rc<str> {
        if let Some(existing) = self.map.get(s) {
            return Rc::clone(existing);
        }
        let rc: Rc<str> = Rc::from(s);
        self.map.insert(s.to_string(), Rc::clone(&rc));
        rc
    }

    /// Interns an already-allocated `Rc<str>`, reusing its allocation if
    /// the string content is new to the interner.
    #[inline]
    pub fn intern_rc(&mut self, rc: &Rc<str>) -> Rc<str> {
        let s: &str = rc.as_ref();
        if let Some(existing) = self.map.get(s) {
            return Rc::clone(existing);
        }
        self.map.insert(s.to_string(), Rc::clone(rc));
        Rc::clone(rc)
    }

    /// Clears all interned strings. Called on VM reset between executions.
    pub fn clear(&mut self) {
        self.map.clear();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn intern_deduplicates() {
        let mut interner = StringInterner::new();
        let a = interner.intern("hello");
        let b = interner.intern("hello");
        assert!(Rc::ptr_eq(&a, &b));
    }

    #[test]
    fn intern_rc_deduplicates() {
        let mut interner = StringInterner::new();
        let rc1: Rc<str> = Rc::from("world");
        let rc2: Rc<str> = Rc::from("world");
        assert!(!Rc::ptr_eq(&rc1, &rc2));

        let a = interner.intern_rc(&rc1);
        let b = interner.intern_rc(&rc2);
        assert!(Rc::ptr_eq(&a, &b));
    }

    #[test]
    fn intern_and_intern_rc_share() {
        let mut interner = StringInterner::new();
        let a = interner.intern("shared");
        let rc: Rc<str> = Rc::from("shared");
        let b = interner.intern_rc(&rc);
        assert!(Rc::ptr_eq(&a, &b));
    }

    #[test]
    fn clear_resets() {
        let mut interner = StringInterner::new();
        let a = interner.intern("temp");
        interner.clear();
        let b = interner.intern("temp");
        assert!(!Rc::ptr_eq(&a, &b));
    }
}

