/// Type alias for native function callables.
///
/// Native functions receive a slice of [`Value`] arguments and return
/// either a [`Value`] result or a `String` error message.
pub type NativeFn = Rc<dyn Fn(&[Value]) -> Result<Value, String>>;

/// Type alias for native method callables.
///
/// Native methods receive the receiver value and a slice of arguments,
/// and return either a [`Value`] result or a `String` error message.
pub type NativeMethodFn = Rc<dyn Fn(&Value, &[Value]) -> Result<Value, String>>;

/// A host-registered native function callable from Writ scripts.
pub struct NativeFunction {
    /// The function name as seen by scripts.
    pub name: String,
    /// Optional module this function belongs to (for `disable_module` filtering).
    pub module: Option<String>,
    /// Expected argument count. `None` means variadic.
    pub arity: Option<u8>,
    /// The callable body.
    pub body: NativeFn,
}

impl NativeFunction {
    /// Constructs a `NativeFunction` from a typed handler.
    /// Arity is inferred from the handler's type.
    pub fn from_handler<H: IntoNativeHandler>(
        name: &str,
        module: Option<&str>,
        handler: H,
    ) -> Self {
        NativeFunction {
            name: name.to_string(),
            module: module.map(|m| m.to_string()),
            arity: H::arity(),
            body: handler.into_handler(),
        }
    }
}

/// A host-registered method callable on a specific value type.
pub struct NativeMethod {
    /// The method name as seen by scripts.
    pub name: String,
    /// Optional module this method belongs to (for `disable_module` filtering).
    pub module: Option<String>,
    /// Expected argument count (not including the receiver). `None` means variadic.
    pub arity: Option<u8>,
    /// The callable body. Receives the receiver value and arguments.
    pub body: NativeMethodFn,
}

impl NativeMethod {
    /// Constructs a `NativeMethod` from a typed handler.
    /// Arity is inferred from the handler's type.
    pub fn from_handler<H: IntoNativeMethodHandler>(
        name: &str,
        module: Option<&str>,
        handler: H,
    ) -> Self {
        NativeMethod {
            name: name.to_string(),
            module: module.map(|m| m.to_string()),
            arity: H::arity(),
            body: handler.into_method_handler(),
        }
    }
}

use std::any::Any;

use super::value::Value;

/// Trait for host-owned types exposed to Writ scripts.
///
/// Implement this trait on Rust types that need to be accessible
/// from Writ scripts via `VM::register_type`. Scripts can read/write
/// fields and call methods on objects implementing this trait.
pub trait WritObject: std::fmt::Debug + 'static {
    /// Returns the type name as seen by scripts (e.g. `"Player"`).
    fn type_name(&self) -> &str;

    /// Gets a field value by name.
    fn get_field(&self, name: &str) -> Result<Value, String>;

    /// Sets a field value by name.
    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String>;

    /// Calls a method by name with the given arguments.
    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String>;

    /// Gets a field value by pre-computed hash (hot path for VM).
    /// Default falls back to `get_field(name)`.
    fn get_field_by_hash(&self, _hash: u32, name: &str) -> Result<Value, String> {
        self.get_field(name)
    }

    /// Sets a field value by pre-computed hash (hot path for VM).
    /// Default falls back to `set_field(name, value)`.
    fn set_field_by_hash(&mut self, _hash: u32, name: &str, value: Value) -> Result<(), String> {
        self.set_field(name, value)
    }

    /// Returns self as `&dyn Any` for downcasting to concrete types.
    fn as_any(&self) -> &dyn Any;
}

impl WritObject for Box<dyn WritObject> {
    fn type_name(&self) -> &str {
        (**self).type_name()
    }
    fn get_field(&self, name: &str) -> Result<Value, String> {
        (**self).get_field(name)
    }
    fn set_field(&mut self, name: &str, value: Value) -> Result<(), String> {
        (**self).set_field(name, value)
    }
    fn call_method(&mut self, name: &str, args: &[Value]) -> Result<Value, String> {
        (**self).call_method(name, args)
    }
    fn get_field_by_hash(&self, hash: u32, name: &str) -> Result<Value, String> {
        (**self).get_field_by_hash(hash, name)
    }
    fn set_field_by_hash(&mut self, hash: u32, name: &str, value: Value) -> Result<(), String> {
        (**self).set_field_by_hash(hash, name, value)
    }
    fn as_any(&self) -> &dyn Any {
        (**self).as_any()
    }
}

use std::cell::RefCell;
use std::collections::HashMap;
